insert into public.cours (matiere_id, titre, contenu, source, ordre) values
  ('poo', 'Environnement virtuel Python', 'Espace isolé pour installer des dépendances par projet. Créé avec `python -m venv iai` puis activé via `Scripts\activate` (Windows) ou `source bin/activate` (Linux).', 'Cours intégré POO Avancée', 0),
  ('poo', 'Architecture MVT de Django', 'Django suit le pattern Modèle-Vue-Template : modèle (ORM), vue (logique métier), template (HTML). Un projet contient plusieurs apps réutilisables.', 'Cours intégré POO Avancée', 1),
  ('poo', 'Modèles et ORM Django', 'Les modèles héritent de `models.Model` et définissent des champs typés (CharField, IntegerField, BooleanField, DateTimeField, JSONField). L''ORM traduit en SQL automatiquement.', 'Cours intégré POO Avancée', 2),
  ('poo', 'Migrations Django', 'Versionnage du schéma DB. `makemigrations` génère les fichiers, `migrate` les applique. Django gère un graphe de dépendances pour la cohérence.', 'Cours intégré POO Avancée', 3),
  ('poo', 'Vues (FBV et CBV)', 'FBV : fonctions Python recevant HttpRequest et retournant HttpResponse. CBV : classes génériques (ListView, CreateView, DetailView) favorisant la réutilisation.', 'Cours intégré POO Avancée', 4),
  ('poo', 'Templates et formulaires', 'Syntaxe `{{ variable }}` et `{% tag %}`. Les ModelForm automatisent HTML + validation. `{% csrf_token %}` est obligatoire pour les POST.', 'Cours intégré POO Avancée', 5),
  ('poo', 'Routage URLs', 'Configuration dans `urls.py` projet + apps. `urlpatterns` lie chemin (path/re_path) à une vue. `include()` organise modulairement.', 'Cours intégré POO Avancée', 6),
  ('poo', 'Middleware Django', 'Couche de traitement entre requête et réponse. CsrfViewMiddleware (protection CSRF), AuthenticationMiddleware (utilisateur courant), SessionMiddleware (sessions).', 'Cours intégré POO Avancée', 7),
  ('poo', 'Vues asynchrones', 'Depuis Django 3.1, on peut écrire `async def` déployées via ASGI (Daphne, Uvicorn). Idéal pour I/O concurrents (API, BD).', 'Cours intégré POO Avancée', 8),
  ('poo', 'Optimisation ORM', '`select_related()` fait des JOIN SQL pour ForeignKey/OneToOne. `prefetch_related()` fait des requêtes séparées pour ManyToMany. `only()`/`defer()` limitent les colonnes.', 'Cours intégré POO Avancée', 9),
  ('poo', 'Django REST Framework', 'Extension pour APIs REST. Pagination personnalisée via classes héritant de BasePagination (PageNumberPagination, LimitOffsetPagination).', 'Cours intégré POO Avancée', 10),
  ('poo', 'Signaux Django', 'Mécanisme de découplage : `pre_save`, `post_save`, `pre_delete`. Implémentés via `@receiver` connecté à un sender (modèle).', 'Cours intégré POO Avancée', 11),
  ('mobile', 'Flutter et le multiplateforme', 'Framework open-source Google (2018) pour apps Android/iOS/Web/Desktop depuis une seule base Dart. Moteur Skia/Impeller, 60/120 FPS.', 'Cours intégré Programmation Mobile', 0),
  ('mobile', 'Le langage Dart', 'Langage exclusif de Flutter, fortement typé, OO. Compile AOT (production) et JIT (dev). Null Safety. Mots-clés : var, final (runtime), const (compilation), late.', 'Cours intégré Programmation Mobile', 1),
  ('mobile', 'Widgets : tout est Widget', 'Toute l''interface est un arbre de widgets immuables. StatelessWidget (sans état : Text, Icon) vs StatefulWidget (état mutable via setState : formulaires, compteurs).', 'Cours intégré Programmation Mobile', 2),
  ('mobile', 'Cycle de vie StatefulWidget', 'createState() → initState() → didChangeDependencies() → build() → didUpdateWidget() → setState() (déclenche rebuild) → dispose() (libère les ressources).', 'Cours intégré Programmation Mobile', 3),
  ('mobile', 'Layouts Flutter', 'Row, Column, Stack (+ Positioned), Container (margin/padding/decoration), Expanded/Flexible, GridView, ListView, Padding, Center, SizedBox, Align. Scaffold = structure page.', 'Cours intégré Programmation Mobile', 4),
  ('mobile', 'BuildContext', 'Position du widget dans l''arbre. Donne accès aux ancêtres et InheritedWidgets : Theme.of(context), MediaQuery.of(context), Navigator.of(context), Provider.of<T>(context).', 'Cours intégré Programmation Mobile', 5),
  ('mobile', 'Navigation et routage', 'Navigator gère une pile de routes. push() empile, pop() dépile, pushReplacement() remplace, pushAndRemoveUntil() vide. Routes nommées dans MaterialApp.', 'Cours intégré Programmation Mobile', 6),
  ('mobile', 'Gestion d''état', 'setState() pour l''état local. Provider (ChangeNotifier + notifyListeners + Consumer), Riverpod, BLoC/Cubit (logique séparée), GetX, InheritedWidget.', 'Cours intégré Programmation Mobile', 7),
  ('mobile', 'ListView et listes dynamiques', 'ListView.builder pour lazy loading (longues listes). ListView.separated pour séparateurs. GridView.builder pour grille. FutureBuilder (Future unique), StreamBuilder (Stream multi-valeurs).', 'Cours intégré Programmation Mobile', 8),
  ('mobile', 'Animations Flutter', 'AnimationController (vsync via SingleTickerProviderStateMixin) + Tween (plage de valeurs) + CurvedAnimation (easeIn, bounceOut). AnimatedBuilder reconstruit. Toujours dispose().', 'Cours intégré Programmation Mobile', 9),
  ('mobile', 'Firebase et persistance', 'Auth (email, Google, phone), Firestore (NoSQL temps réel), Realtime DB, Storage, FCM, Analytics. Init dans main() : Firebase.initializeApp() après WidgetsFlutterBinding.ensureInitialized().', 'Cours intégré Programmation Mobile', 10),
  ('mobile', 'Hot Reload et outils', 'Hot Reload (''r'') < 1s, garde l''état. Hot Restart (''R'') redémarre. pubspec.yaml déclare dépendances + assets. flutter doctor diagnostique.', 'Cours intégré Programmation Mobile', 11),
  ('data', 'Définition et objectifs de l''ADD', 'Ensemble de méthodes descriptives pour résumer, organiser et visualiser l''information d''un grand tableau multidimensionnel afin d''en révéler la structure (Fénelon).', 'Cours intégré Analyse des Données', 0),
  ('data', 'Statistiques descriptives de base', 'Moyenne : résume une série par un nombre. Variance : dispersion (moy. des carrés des écarts). Écart-type : √variance. Covariance : liaison linéaire entre 2 variables.', 'Cours intégré Analyse des Données', 1),
  ('data', 'Méthodes descriptives vs explicatives', 'Descriptives : ACP, AFC, CAH (résument sans variable cible). Explicatives : régression, analyse discriminante, ANOVA (expliquent une variable par d''autres).', 'Cours intégré Analyse des Données', 2),
  ('data', 'Types de mesure des variables', 'Nominale (catégories sans ordre : sexe). Ordinale (catégories ordonnées : classes d''âge). Métrique (quantitative : investissement). Le type détermine la méthode.', 'Cours intégré Analyse des Données', 3),
  ('data', 'Analyse en Composantes Principales (ACP)', 'Méthode descriptive résumant un tableau n×p de variables quantitatives en q < p nouvelles variables (composantes principales) avec minimum de perte d''information.', 'Cours intégré Analyse des Données', 4),
  ('data', 'Démarche de l''ACP', '1) Centrage-réduction. 2) Matrice variances-covariances/corrélations. 3) Polynôme caractéristique, valeurs/vecteurs propres. 4) Inertie des axes. 5) Sélection des composantes.', 'Cours intégré Analyse des Données', 5),
  ('data', 'Matrice centrée-réduite (MCR)', 'Obtenue en soustrayant la moyenne et divisant par l''écart-type. Résultat : moyenne=0, variance=1. Homogénéise les unités entre variables.', 'Cours intégré Analyse des Données', 6),
  ('data', 'Valeurs propres et inertie', 'Valeurs propres λ issues du polynôme det(U-λI)=0 mesurent l''inertie par axe. % inertie = λi/Σλi (ex : axe 1 = 78%, axe 2 = 22%).', 'Cours intégré Analyse des Données', 7),
  ('data', 'Cercle des corrélations et contributions', 'Variables bien représentées proches du cercle unité (norme ≈ 1). Contribution CTR = poids d''un individu/variable dans la construction d''un axe.', 'Cours intégré Analyse des Données', 8),
  ('data', 'Analyse Factorielle des Correspondances (AFC)', 'Benzécri (1970-1990). Analyse des tableaux de contingence (2 variables qualitatives). Étudie proximité profils-lignes ↔ profils-colonnes. AFC = 2 ACP.', 'Cours intégré Analyse des Données', 9),
  ('data', 'Profils, distance du khi-2', 'Profils-lignes (fij/fi.) et profils-colonnes (fij/f.j). Distance du khi-2 (Euclidienne pondérée). Taux de liaison (fij - fi.f.j)/(fi.f.j) mesure l''écart à l''indépendance.', 'Cours intégré Analyse des Données', 10),
  ('data', 'Classification Ascendante Hiérarchique (CAH)', 'Regroupement progressif des individus les plus proches en classes homogènes → dendrogramme. Différent du k-means (nb classes fixé d''avance).', 'Cours intégré Analyse des Données', 11),
  ('data', 'Distances et CAH', 'Étapes : centrage-réduction, matrice de proximité (Euclidienne, Euclidienne²,  Manhattan, Tchebychev), agrégation par saut minimum (ou Ward), dendrogramme.', 'Cours intégré Analyse des Données', 12),
  ('web', 'Architecture MVC Laravel', 'Laravel = framework PHP basé sur MVC. Sépare logique métier (Modèles Eloquent), présentation (Vues Blade), routage (Contrôleurs). Code maintenable et testable.', 'Cours intégré Outils de Prog. Web', 0),
  ('web', 'Routes Laravel', 'routes/web.php (sessions+CSRF) ou routes/api.php (préfixe /api, JSON, stateless). Syntaxe : Route::get(''/products'', [Controller::class, ''index'']). Routes nommées, groupes, middlewares.', 'Cours intégré Outils de Prog. Web', 1),
  ('web', 'Routes Resource et API Resource', 'Route::resource → 7 routes CRUD (index, create, store, show, edit, update, destroy). Route::apiResource → 5 routes (sans create/edit). Filtrer avec ->only() / ->except().', 'Cours intégré Outils de Prog. Web', 2),
  ('web', 'Contrôleurs', 'app/Http/Controllers regroupent la logique. Création : php artisan make:controller NomController --resource (génère les 7 méthodes CRUD).', 'Cours intégré Outils de Prog. Web', 3),
  ('web', 'Modèles Eloquent (ORM)', 'Chaque modèle = une table. Propriétés : $fillable (mass-assignable), $guarded, $hidden (masqué en JSON). Méthodes : find, where, save, create, update, delete.', 'Cours intégré Outils de Prog. Web', 4),
  ('web', 'Migrations', 'Versionnage du schéma DB. php artisan make:migration, migrate (exécute), migrate:rollback (annule dernier batch), migrate:fresh (réinitialise tout).', 'Cours intégré Outils de Prog. Web', 5),
  ('web', 'Relations Eloquent', 'hasOne/belongsTo (1:1), hasMany/belongsTo (1:N), belongsToMany (N:N via pivot), hasManyThrough, morphTo/morphMany (polymorphique : colonnes _id + _type).', 'Cours intégré Outils de Prog. Web', 6),
  ('web', 'Vues Blade', 'Moteur de templating. {{ $var }} avec échappement HTML, {!! $var !!} sans échappement. @if, @foreach, @extends, @yield, @section pour la logique et l''héritage.', 'Cours intégré Outils de Prog. Web', 7),
  ('web', 'Middlewares', 'Filtrent les requêtes HTTP (auth, CORS, logs, throttle). Appliqués via ->middleware(''auth''). Créés via php artisan make:middleware, enregistrés dans Kernel.php (ou bootstrap/app.php en L11).', 'Cours intégré Outils de Prog. Web', 8),
  ('web', 'Validation et FormRequest', '$request->validate([...]) ou FormRequest dédiée. Règles : required, email, unique, min, max, numeric, exists. Méthode rules() dans le FormRequest.', 'Cours intégré Outils de Prog. Web', 9),
  ('web', 'Authentification, Gates, Policies', 'Breeze/Jetstream pour scaffolding, Sanctum/Passport pour API. Gate::define = autorisation perso. Policies = ensemble d''autorisations liées à un modèle. Middleware ''auth'' protège.', 'Cours intégré Outils de Prog. Web', 10),
  ('web', 'Artisan CLI et Composer', 'Artisan : make:controller, make:model, make:migration, migrate, route:list, tinker (REPL), serve. Composer gère les dépendances PHP via composer.json (autoload PSR-4).', 'Cours intégré Outils de Prog. Web', 11),
  ('web', 'Service Providers et Conteneur', 'ServiceProviders (app/Providers) enregistrent les services. register() lie ; boot() exécute après chargement. Les Facades = pattern Facade pour accès statique aux services.', 'Cours intégré Outils de Prog. Web', 12),
  ('web', 'API REST avec Laravel', 'routes/api.php (préfixe /api, JSON). Sanctum/Passport = auth par token. API Resources transforment les modèles en JSON structuré. GET/POST/PUT/PATCH/DELETE.', 'Cours intégré Outils de Prog. Web', 13),
  ('web', 'Query Builder vs Eloquent', 'Query Builder (DB::table()->...) plus rapide, idéal pour requêtes complexes/batch. Eloquent plus expressif (relations, events) mais plus lourd. Les deux retournent Collections.', 'Cours intégré Outils de Prog. Web', 14),
  ('ia', 'Définition de l''IA', 'L''IA conçoit des programmes capables d''apprendre, de raisonner et de résoudre des problèmes complexes, par opposition aux programmes classiques qui suivent des instructions prédéfinies. IA faible (spécialisée : Siri, AlphaGo), IA forte/AGI (égale l''humain, théorique), super-IA/ASI. ELIZA (1966, Weizenbaum) = 1er chatbot. John McCarthy (conférence Dartmouth 1956) = père de l''IA.', 'Cours intégré Intro. à l''IA', 0),
  ('ia', 'Données, Big Data et Data Science', 'Une donnée est toute information enregistrée numériquement (texte, photo, email, poésie écrite, vidéo, capteur). Une idée orale non enregistrée n''est PAS une donnée. Big Data = données massives caractérisées par les 5V (Volume, Vélocité, Variété, Véracité, Valeur). Data Science : analyser ces données + prédire actions/comportements futurs.', 'Cours intégré Intro. à l''IA', 1),
  ('ia', 'Hiérarchie IA/ML/Deep Learning', 'IA = domaine le plus large. Machine Learning = sous-discipline de l''IA (apprend des données sans être explicitement programmé). Deep Learning = sous-discipline du ML (réseaux profonds multi-couches). Inclusion : DL ⊂ ML ⊂ IA ⊂ Data Science.', 'Cours intégré Intro. à l''IA', 2),
  ('ia', 'Types d''apprentissage', '1) Supervisé : données étiquetées (caractéristiques + cibles fournies). Ex : classification d''images, détection de spam. 2) Non supervisé : structures découvertes seules dans des données non étiquetées (clustering, k-means). 3) Par renforcement (essai/erreur) : agent + environnement + récompenses. Ex : AlphaGo, jeux vidéo, robotique.', 'Cours intégré Intro. à l''IA', 3),
  ('ia', 'Pipeline d''un projet IA', '(1) Définition du problème ; (2) Collecte des données ; (3) Exploration (visualisation, stats descriptives) ; (4) Nettoyage : valeurs manquantes/aberrantes, doublons, normalisation ; (5) Modélisation : règles mathématiques + choix d''algo ; (6) Entraînement (sur partie des données extraites de l''exploration) ; (7) Évaluation ; (8) Déploiement et suivi.', 'Cours intégré Intro. à l''IA', 4),
  ('ia', 'Régression logistique', 'Algorithme de classification (malgré son nom) qui utilise la fonction sigmoïde / logistique σ(x)=1/(1+e⁻ˣ) pour produire une sortie entre 0 et 1 interprétée comme probabilité. Surtout pour problèmes binaires. Sklearn fournit LogisticRegression. Autres activations : ReLU, tanh, softmax.', 'Cours intégré Intro. à l''IA', 5),
  ('ia', 'Réseaux de neurones et Deep Learning', 'Inspirés du cerveau : couches (entrée/cachées/sortie) reliées par poids. Chaque neurone = somme pondérée + biais + activation. Entraînement par rétropropagation du gradient. Anti-surapprentissage : L1/L2, data augmentation, Dropout (désactivation aléatoire). Frameworks : TensorFlow, Keras, PyTorch.', 'Cours intégré Intro. à l''IA', 6),
  ('ia', 'CNN (Convolutional Neural Networks)', 'Réseau profond spécialisé en vision. Convolution = filtrer l''image en petits carrés (kernels) qui détectent motifs locaux (bords, textures). Couches : convolution + pooling (réduction) + dense (classification). Créés via TensorFlow/PyTorch. Applications : reconnaissance d''images, détection d''objets, vision médicale.', 'Cours intégré Intro. à l''IA', 7),
  ('ia', 'Recherche : BFS et DFS', 'BFS (Breadth-First, en largeur) : FILE FIFO, niveau par niveau, trouve le plus court chemin (graphe non pondéré). DFS (Depth-First, en profondeur) : PILE LIFO, explore loin avant de revenir, économe en mémoire mais non optimal. Tous deux : trace des visités (set) pour éviter boucles. Bifurcation : BFS visite tous les voisins, DFS s''enfonce dans une branche.', 'Cours intégré Intro. à l''IA', 8),
  ('ia', 'Recherche informée (A*)', 'Utilise une heuristique h(n) pour estimer la distance restante. A* combine coût réel g(n) et heuristique : f(n)=g(n)+h(n). Si h admissible (ne surestime jamais), A* optimal. Vs recherche aveugle (BFS/DFS) qui explore sans guide. Ex : trouver un étudiant → BFS visite bâtiment par bâtiment, A* utilise distance euclidienne au dernier emplacement connu.', 'Cours intégré Intro. à l''IA', 9),
  ('ia', 'Biais algorithmique et éthique', 'Distorsion systématique défavorisant un groupe, due aux données/labels/conception. Ex : femmes sous-représentées historiquement aux postes à responsabilité = modèle RH biaisé. Solutions : équilibrage du dataset, métriques d''équité, explicabilité (XAI/SHAP/LIME), RGPD, IA Act, diversité des équipes, monitoring.', 'Cours intégré Intro. à l''IA', 10),
  ('ia', 'Applications et impact sociétal', 'Vision (reconnaissance d''image), NLP (chatbots, traduction), systèmes de recommandation, voitures autonomes, médecine (diagnostic), finance (fraude), industrie (maintenance prédictive). Deepfakes = trucages hyperréalistes (GAN). Marché du travail : automatise tâches précises/routinières, ne remplace pas encore l''humain partout, n''éprouve pas d''émotions.', 'Cours intégré Intro. à l''IA', 11),
  ('english', 'Communication Process', 'Sender → Message → Channel → Receiver → Feedback (+ Context, Noise). Le téléphone n''est PAS un élément du processus, juste un canal. Exemple : un dev envoie un Slack (channel) à son lead (receiver) qui répond OK (feedback).', 'Cours intégré English Expert', 0),
  ('english', 'Verbal vs Non-Verbal', 'Verbal = WORDS, parlés ou écrits (talking, emails, reports). Non-verbal = SANS mots : facial expressions, gestures, eye contact, body language, posture, tone. Attention : ''spoken words'' = verbal ; ''gestures'', ''eye contact'' = non-verbal.', 'Cours intégré English Expert', 1),
  ('english', 'Business Communication', 'Formelle, claire, concise, orientée objectif. Key features : Clarity, Conciseness, Formality, Accuracy, Professionalism, Purpose-driven. Formel = business email. Informel = chatting at party, jokes, talking to friend.', 'Cours intégré English Expert', 2),
  ('english', 'Structure d''un Formal Email', '5 parties obligatoires : (1) SUBJECT précis ; (2) GREETING (''Dear Team,'', ''Dear Mr. Smith,'') ; (3) PURPOSE/BODY (''I am writing to inform you...'') ; (4) TIME & DATE précis ; (5) CLOSING (''Best regards,'', ''Kind regards,'', ''Sincerely,'' + nom + fonction).', 'Cours intégré English Expert', 3),
  ('english', 'IT Core Vocabulary', 'Debug = corriger bugs ; Deploy = mise en prod ; Backend/Frontend = serveur/client ; Framework = cadre ; Repository = dépôt Git ; Branch/Merge/Commit ; Pull Request (PR) ; Deprecated = obsolète ; Scalability = montée en charge ; Latency = temps de réponse ; Payload = données transmises ; Endpoint = URL API ; Build/Release/Rollback ; Pipeline CI/CD ; Stack = pile tech.', 'Cours intégré English Expert', 4),
  ('english', 'Reading Technical Docs', 'Verbes impératifs : install, configure, run, build, deploy, return, throw. Structures : ''This method returns...'', ''The function takes...'', ''Make sure to...'', ''Refer to...'', ''Note that...''. Abréviations : i.e., e.g., N.B., RFC. Sections : Overview, Prerequisites, Installation, Usage, API Reference, Troubleshooting.', 'Cours intégré English Expert', 5),
  ('english', 'Professional Idioms', 'Get the ball rolling = démarrer. Low-hanging fruit = tâches faciles à gain rapide. Deep dive = analyse approfondie. Touch base = faire un point. Circle back = revenir plus tard. On the same page = être d''accord. Move the needle = impact significatif. Think outside the box = sortir des sentiers battus. ASAP / EOD / FYI.', 'Cours intégré English Expert', 6),
  ('english', 'Tense Usage', 'Present simple : habitudes/fonctionnement (''The API returns JSON''). Present continuous : action en cours (''I am debugging''). Present perfect : action passée + impact présent (''I have deployed''). Past simple : terminée (''Yesterday I merged''). Will/going to : futur. Modals : should/must/could/would. Erreur fréquente : ''I have did'' ❌ → ''I have done'' ✓.', 'Cours intégré English Expert', 7),
  ('english', 'Active vs Passive Voice', 'Active : The dev fixed the bug. Passive : The bug was fixed (by the dev). Formation : be + past participle. Très courant en docs/release notes : ''The server has been restarted'', ''The endpoint is called every 5s'', ''The data is encrypted before transmission''.', 'Cours intégré English Expert', 8),
  ('english', 'Confusing Words (faux-amis)', 'Library (bib. de code) ≠ librairie (bookstore). Eventually = finalement ≠ éventuellement (possibly). Actually = en fait ≠ actuellement (currently). To assist = aider ≠ assister à (to attend). Sensible = sensé ≠ sensible (sensitive). Deception = tromperie ≠ déception (disappointment). Support = soutenir ≠ supporter (to tolerate).', 'Cours intégré English Expert', 9),
  ('english', 'Meeting Vocabulary', 'Standup/daily, sprint planning, sprint review/demo, retrospective (retro), kickoff, set up a meeting, reschedule, attend, agenda, minutes, action items, blocker, stakeholder, deadline, milestone, deliverable, follow up.', 'Cours intégré English Expert', 10),
  ('english', 'Bug Reporting', 'Steps to reproduce, expected behavior, actual behavior, severity (critical/major/minor), priority, stack trace, workaround, hotfix, patch, root cause, side effect, edge case. Phrases : ''I am encountering an issue with...'', ''The application crashes when...'', ''The endpoint returns 500 instead of 200''.', 'Cours intégré English Expert', 11),
  ('secubd', 'Définition et périmètre de la sécurité des BD', 'La sécurité des bases de données est un ensemble de moyens, de contrôles et de mesures conçus pour protéger les BD contre les menaces accidentelles et intentionnelles afin de préserver la confidentialité, l''intégrité et la disponibilité (triade CIA) des données. Elle couvre quatre éléments : les données de la BD, le SGBD, toutes les applications associées et le serveur (physique ou virtuel). Sa portée s''étend de la sécurité physique du matériel à la sécurité logicielle des applications, en passant par les contrôles d''accès et d''administration. Les conséquences d''une violation incluent la compromission de la propriété intellectuelle, l''interruption des opérations, des coûts de remédiation (enquête, forensique, juridique), et l''atteinte à la réputation.', 'Cours intégré Sécurité des BD', 0),
  ('secubd', 'Les trois piliers CIA (Confidentialité, Intégrité, Disponibilité)', 'L''intégrité garantit que les données ne sont ni modifiées ni falsifiées par des parties non autorisées, à travers les contraintes d''intégrité (menaces : données valides mais inexactes, données invalides, abus de privilèges légitimes). La disponibilité assure l''accessibilité des données 24h/24 - 7j/7 (menaces : crash de disque, panne matérielle/logicielle, attaques DoS). La confidentialité garantit que seules les personnes ou programmes autorisés accèdent aux données (menaces : accès non autorisé, copies illicites de données sensibles, vente illégale).', 'Cours intégré Sécurité des BD', 1),
  ('secubd', 'Processeur de sécurité et politique d''accès', 'Le processeur de sécurité (contrôleur d''accès) intercepte chaque requête, la confronte aux règles d''accès dérivées de la politique de sécurité, et l''autorise, la refuse ou la modifie. Il s''agit du cœur de l''application des autorisations dans un SGBD. Les règles d''accès traduisent en langage technique la politique de sécurité formalisée par l''organisation.', 'Cours intégré Sécurité des BD', 2),
  ('secubd', 'Typologie des attaques sur une BD', 'On distingue les attaques non frauduleuses (catastrophes naturelles, pannes matérielles/logicielles, erreurs humaines, coupures de courant, mots de passe faibles) et les attaques frauduleuses (internes ou externes) : abus de privilège excessif, abus de privilège légitime, élévation de privilèges (horizontale ou verticale), injection SQL, déni de service (DoS/DDoS). Les pirates sont classés en pirates externes, pirates utilisateurs (reconnus du SGBD) et pirates administrateurs.', 'Cours intégré Sécurité des BD', 3),
  ('secubd', 'Injection SQL : principe et contournement d''authentification', 'L''injection SQL consiste à contrefaire une instruction SQL en injectant du code hors des limites de l''entrée utilisateur attendue, pour altérer, voler ou détruire des données. Exemple de contournement d''authentification avec l''opérateur OR : SELECT * FROM users WHERE username=''admin'' OR ''1''=''1'' AND password=''demo''. Les payloads classiques sont '', --, #, ;, ). En MySQL, AND est évalué avant OR. Les injections sur BD relationnelles (MySQL, Oracle, MS SQL) s''opposent aux injections NoSQL sur MongoDB/CouchDB. Prévention : requêtes paramétrées (prepared statements), validation/échappement des entrées, ORM, principe du moindre privilège pour le compte applicatif.', 'Cours intégré Sécurité des BD', 4),
  ('secubd', 'Vues sécurisées et masquage de données', 'Une vue est une table virtuelle qui contient le résultat d''une requête (sans stocker les données) et permet de masquer certains champs aux utilisateurs et de personnaliser l''affichage selon le profil. Exemple : CREATE VIEW v_secdaac AS SELECT etudiant.sexe, note.code, note.note FROM etudiant INNER JOIN note ON etudiant.matricule = note.matricule ; puis GRANT SELECT ON v_secdaac TO ''secdaac''@''localhost''. La vue est un outil de masquage et de filtrage horizontal/vertical des données.', 'Cours intégré Sécurité des BD', 5),
  ('secubd', 'Authentification et mots de passe robustes', 'L''authentification confirme l''identité d''un utilisateur tentant de se connecter à la BD. Bonnes pratiques : mots de passe forts (longueur, complexité, expiration), hashage par bcrypt ou Argon2 (avec sel et facteur de coût), MFA, suppression des comptes par défaut, rotation régulière des secrets, coffre-fort numérique pour les comptes à privilèges, supervision des activités d''admin pour détecter Pass-the-Hash, brute force et password spraying.', 'Cours intégré Sécurité des BD', 6),
  ('secubd', 'Contrôle d''accès : sujets, objets, opérations, règles', 'Un système de contrôle d''accès comprend : les sujets (entités actives : utilisateurs, processus), les objets (entités passives : tables, fichiers, vues), les opérations (lecture, écriture, ajout, suppression, exécution) et un ensemble de règles d''accès reflétant la politique de sécurité. Le SGBD autorise, modifie ou interdit les requêtes selon ces règles.', 'Cours intégré Sécurité des BD', 7),
  ('secubd', 'Modèle DAC (Discretionary Access Control)', 'Le DAC repose sur 4 principes : (1) le créateur d''un objet en est le propriétaire, (2) le propriétaire peut transmettre/retirer des autorisations à sa discrétion, (3) il peut déléguer le droit de transmission, (4) tout ce qui n''est pas autorisé est interdit. Implémenté via les matrices de contrôle d''accès de Lampson (1971) – triplet (S, O, M) – et HRU (Harrison, Ruzzo, Ullman 1976) – quadruplet (S, O, R, M) avec 6 opérations primitives (enter a, delete a, create/delete subject, create/delete object). Avantages : simple, flexible, intégré aux SGBD. Inconvénients : risque d''explosion des ACL, ne reflète pas les flux réels, vulnérable aux chevaux de Troie.', 'Cours intégré Sécurité des BD', 8),
  ('secubd', 'Modèle MAC (Mandatory Access Control)', 'Le MAC est destiné aux SI où la préservation du secret est critique (défense, gouvernement). Les objets reçoivent une classification (Top Secret >= Secret >= Confidentiel >= Non Classifié) et les sujets une habilitation. Modèle Bell-LaPadula (BLP, 1973, confidentialité) : SS-propriété ''no read up'' (un sujet ne lit un objet que si son habilitation est >= classification de l''objet) et propriété étoile ''no write down'' (écriture seulement si habilitation <= classification de l''objet). Modèle Biba (1977, intégrité) : ''no read down'' et ''no write up'' – le miroir inverse pour empêcher la corruption de données de haute intégrité par du contenu de plus bas niveau. Avantages : cohérence, conformité, faible risque. Inconvénients : rigidité, complexité, coût, flexibilité limitée.', 'Cours intégré Sécurité des BD', 9),
  ('secubd', 'Modèle RBAC (Role Based Access Control)', 'Les permissions sont affectées à des rôles reflétant la structure organisationnelle, puis les utilisateurs sont rattachés aux rôles. Un sujet a une permission P ssi il est attribué à un rôle détenant P. Commandes SQL : CREATE ROLE nom_role ; GRANT privileges TO role ; GRANT role TO user ; SET ROLE nom_role ; (activation) ; GRANT role1 TO role2 (hiérarchie). RBAC est idéal pour les entreprises à forte rotation de personnel : on modifie l''affectation user-role sans toucher aux permissions des rôles.', 'Cours intégré Sécurité des BD', 10),
  ('secubd', 'GRANT / REVOKE, privilèges objets vs systèmes', 'Un privilège est un droit accordé à un utilisateur ou processus. Les privilèges objets concernent des opérations précises sur des tables/vues (SELECT, INSERT, UPDATE, DELETE, REFERENCES). Les privilèges systèmes concernent la structure (CREATE ANY TABLE, ALTER USER, GRANT OPTION). Syntaxe : GRANT SELECT, INSERT ON schema.table TO user ; REVOKE INSERT ON schema.table FROM user ; L''option WITH GRANT OPTION permet la délégation.', 'Cours intégré Sécurité des BD', 11),
  ('secubd', 'Principe du moindre privilège et politique de gestion', 'Le moindre privilège accorde à un utilisateur uniquement l''accès minimum requis pour sa fonction. Mise en œuvre : (1) auditer tous les comptes à privilèges, (2) éliminer les privilèges admin local inutiles, (3) provisionner les identifiants dans un coffre-fort, (4) renouveler les mots de passe admin après chaque usage, (5) superviser en continu les activités à privilèges. 6 règles de politique : moindre privilège, contrôle de la population, supervision de la délégation, contrôle physique des connexions (restriction aux hôtes connus), limitation des ressources, journalisation des comportements suspects.', 'Cours intégré Sécurité des BD', 12),
  ('secubd', 'Chiffrement (TDE, AES, RSA) et hashage', 'Le chiffrement transparent des données (TDE – Transparent Data Encryption) chiffre les fichiers de données et les journaux au repos sans modifier l''application. Chiffrement symétrique AES (clé partagée, rapide, AES-128/256) pour les volumes. Chiffrement asymétrique RSA (paire clé publique/privée) pour l''échange de clés et la signature. TLS pour le transport client-serveur. Le hashage (SHA-256, bcrypt, Argon2, scrypt) est une fonction à sens unique utilisée pour stocker les mots de passe avec un sel cryptographique pour bloquer les rainbow tables.', 'Cours intégré Sécurité des BD', 13),
  ('secubd', 'Audit, journaux et traçabilité (audit trail)', 'L''audit analyse l''existant pour diagnostiquer et améliorer la BD. On distingue : audit de structure (formes normales, contraintes), audit de qualité (contraintes, doublons), audit de configuration/performances (RAM, CPU, SGA), audit des requêtes (procédures, transactions, tracing), audit d''infrastructure réseau. L''admin doit auditer notamment l''utilisation hors heures ouvrables, la manipulation du schéma, les erreurs, les modifications de procédures stockées. Les audit logs constituent une preuve forensique en cas d''incident.', 'Cours intégré Sécurité des BD', 14),
  ('secubd', 'Sauvegarde, restauration, réplication', 'Sauvegarde complète (full) : copie totale, longue mais simple à restaurer. Sauvegarde incrémentielle : seules les modifications depuis la dernière sauvegarde (rapide, restauration en chaîne). Sauvegarde différentielle : modifications depuis la dernière full (compromis). Stratégie 3-2-1 : 3 copies, 2 supports, 1 hors site. Réplication master-slave/master-master assure haute disponibilité et reprise après incident. Tester régulièrement la restauration. La destruction de données sans sauvegarde est synonyme de dépôt de bilan.', 'Cours intégré Sécurité des BD', 15),
  ('secubd', 'Les 8 étapes de la sécurité des BD (méthodologie)', '1) Découverte (inventaire des BD et données sensibles), 2) Évaluation des vulnérabilités et de la configuration (CIS Benchmarks), 3) Renforcement (hardening : désactivation des comptes par défaut, patching), 4) Audit des modifications de schéma et de configuration, 5) Surveillance de l''activité (DAM – Database Activity Monitoring), 6) Audit applicatif et conformité, 7) Authentification, contrôle d''accès et gestion des droits (RBAC, MFA), 8) Chiffrement (au repos via TDE, en transit via TLS).', 'Cours intégré Sécurité des BD', 16),
  ('secubd', 'Conformité, RGPD et protection des données personnelles', 'Le RGPD (Règlement Général sur la Protection des Données) impose le principe de privacy by design and by default, le consentement explicite, le droit à l''effacement, la notification de violation sous 72h, l''analyse d''impact (PIA/DPIA) pour les traitements à risque. Mesures techniques associées : minimisation des données, pseudonymisation, anonymisation, masquage dynamique (dynamic data masking), chiffrement, journalisation des accès aux données personnelles, suppression contrôlée.', 'Cours intégré Sécurité des BD', 17),
  ('bigdata', 'Définition du Big Data et les 5V', 'Le Big Data (mégadonnées) désigne des ensembles de données dont le volume, la vitesse de génération et la diversité dépassent les capacités des SGBDR traditionnels. Il se caractérise par les 5V : Volume (quantités massives, To-Po), Variété (structurées, semi-structurées JSON/XML, non structurées texte/image/vidéo), Vélocité (vitesse de production et de traitement, souvent en temps réel), Véracité (qualité, fiabilité et cohérence des données) et Valeur (capacité à extraire des insights stratégiques et à transformer les données en décisions).', 'Cours intégré Big Data NoSQL', 0),
  ('bigdata', 'Sources et types de données', 'Les données proviennent de sources hétérogènes : réseaux sociaux, IoT (capteurs connectés), transactions, logs applicatifs, médias, GPS. On distingue : (1) données structurées stockées en SGBDR avec schéma rigide ; (2) données semi-structurées (JSON, XML, YAML) avec schéma flexible ; (3) données non structurées (texte libre, images, vidéos, audio) stockées dans des systèmes de fichiers distribués ; (4) données en temps réel (streaming) nécessitant un traitement instantané.', 'Cours intégré Big Data NoSQL', 1),
  ('bigdata', 'Écosystème Hadoop (HDFS, MapReduce, YARN)', 'Hadoop est un framework open-source de stockage et de traitement distribué. HDFS (Hadoop Distributed File System) découpe les fichiers en blocs (par défaut 128 Mo) répliqués (par défaut x3) sur les DataNodes pilotés par un NameNode. MapReduce est un paradigme de calcul distribué en deux phases : Map (transformation clé-valeur en parallèle) puis Reduce (agrégation par clé). YARN (Yet Another Resource Negotiator) est le gestionnaire de ressources qui orchestre l''allocation CPU/RAM des jobs sur le cluster via le ResourceManager et les NodeManagers.', 'Cours intégré Big Data NoSQL', 2),
  ('bigdata', 'Apache Spark et ses abstractions', 'Spark est un moteur de traitement distribué plus rapide que MapReduce car il effectue les calculs in-memory. Abstractions clés : RDD (Resilient Distributed Dataset, collection distribuée immuable tolérante aux pannes via lineage), DataFrame (structure tabulaire avec schéma, optimisée par Catalyst), Dataset (typé). Modules : Spark SQL (requêtes), Spark Streaming/Structured Streaming (micro-batchs temps réel), MLlib (machine learning), GraphX (graphes). Modèle d''exécution lazy via transformations (map, filter, join) et actions (count, collect, save).', 'Cours intégré Big Data NoSQL', 3),
  ('bigdata', 'Architecture Lambda (batch, speed, serving)', 'L''architecture Lambda combine trois couches pour gérer données massives et temps réel : (1) Batch layer : stocke le master dataset immuable (source de vérité) sur HDFS et calcule des vues agrégées via Hadoop/Spark ; (2) Speed layer : traite les données récentes en streaming (Spark Streaming, Flink, Storm) avec données dénormalisées dans une base NoSQL ; (3) Serving layer : expose les vues batch + temps réel aux clients via une base NoSQL (Cassandra, MongoDB, ElasticSearch). Les clients fusionnent les deux vues pour disposer de données fraîches et corrigées. L''architecture Kappa simplifie en n''utilisant qu''une couche streaming.', 'Cours intégré Big Data NoSQL', 4),
  ('bigdata', 'Théorème CAP et BASE vs ACID', 'Théorème CAP (Brewer) : un système distribué ne peut garantir simultanément que 2 des 3 propriétés : Consistency (cohérence forte, tous les nœuds voient la même donnée à un instant t), Availability (disponibilité, toute requête reçoit une réponse) et Partition tolerance (tolérance aux partitions réseau). En pratique, P est obligatoire donc on choisit entre CP (MongoDB, HBase) et AP (Cassandra, DynamoDB, CouchDB). Les SGBDR appliquent ACID (Atomicité, Cohérence, Isolation, Durabilité) ; les NoSQL appliquent BASE (Basically Available, Soft state, Eventual consistency) : disponibilité prioritaire, état mou, cohérence à terme.', 'Cours intégré Big Data NoSQL', 5),
  ('bigdata', 'Les 4 familles de bases NoSQL', '(1) Clé-Valeur : paires clé→valeur, lecture O(1) par clé, idéal pour cache/session — Redis, Amazon DynamoDB, Riak. (2) Documents : documents auto-descriptifs JSON/BSON regroupés en collections, requêtes riches sur les champs — MongoDB, CouchDB, Couchbase. (3) Colonnes (wide-column) : tables à colonnes dynamiques regroupées en familles, optimisé pour analytique et écriture massive — Apache Cassandra, HBase, ScyllaDB. (4) Graphes : nœuds + relations + propriétés, idéal pour réseaux sociaux et recommandations — Neo4j, Amazon Neptune, ArangoDB.', 'Cours intégré Big Data NoSQL', 6),
  ('bigdata', 'MongoDB : collections, BSON, opérateurs', 'MongoDB est une base orientée documents stockés en BSON (Binary JSON) dans des collections (analogues aux tables). Chaque document a un _id unique. Opérateurs de requête : $eq (=), $ne (≠), $gt/$gte/$lt/$lte, $in/$nin (appartenance), $and/$or/$not, $exists, $regex. Opérateurs de mise à jour : $set (modifier un champ), $unset (supprimer), $inc (incrémenter), $push/$pull (manipuler tableaux), $addToSet (ajouter sans doublon). Le pipeline d''agrégation enchaîne des étapes : $match (filtrage), $group (regroupement), $project (projection), $sort, $limit, $lookup (jointure).', 'Cours intégré Big Data NoSQL', 7),
  ('bigdata', 'MongoDB : indexation, sharding, replica sets', 'Indexes (B-Tree par défaut) accélèrent les requêtes : index simple, composé, multikey (tableaux), texte, géospatial, TTL. Replica Set : groupe de mongod avec 1 primaire (lectures/écritures) et N secondaires (réplication asynchrone + failover automatique via élection). Sharding : partitionnement horizontal des données entre shards selon une shard key (hashée ou rangée), orchestré par mongos et un cluster de config servers. Sharding scale les écritures, replica sets assurent haute disponibilité et tolérance aux pannes.', 'Cours intégré Big Data NoSQL', 8),
  ('bigdata', 'Redis : types de données et TTL', 'Redis est une base clé-valeur en mémoire (in-memory) ultra-rapide, utilisée comme cache, broker de messages ou compteurs. Types : Strings (valeur simple, max 512 Mo), Lists (listes chaînées, LPUSH/RPUSH/LRANGE), Sets (ensembles non ordonnés, SADD/SINTER), Sorted Sets / ZSets (ensembles ordonnés par score, ZADD/ZRANGE, idéal classements), Hashes (objets champ→valeur, HSET/HGET), Streams, Bitmaps, HyperLogLog. TTL (Time To Live) : EXPIRE clé secondes pour expiration automatique. Persistance via RDB (snapshots) ou AOF (append-only file).', 'Cours intégré Big Data NoSQL', 9),
  ('bigdata', 'Cassandra : CQL et clés de partition', 'Apache Cassandra est une base colonnes distribuée AP, architecture peer-to-peer sans nœud maître (anneau de hachage cohérent). CQL (Cassandra Query Language) ressemble à SQL mais sans jointures. Clé primaire = partition key (détermine le nœud de stockage, distribution) + clustering key (tri à l''intérieur d''une partition). Exemple : PRIMARY KEY ((user_id), timestamp DESC). Niveaux de cohérence ajustables (ONE, QUORUM, ALL). Écritures via Memtable + Commit Log puis flush en SSTables. Idéal pour séries temporelles et IoT.', 'Cours intégré Big Data NoSQL', 10),
  ('bigdata', 'Neo4j et Cypher', 'Neo4j est la base de données graphe la plus utilisée, modèle Property Graph : nœuds (entités avec labels), relations (orientées, typées, avec propriétés). Cypher est le langage de requête déclaratif : MATCH (pattern matching), CREATE (création), MERGE (création si absent, sinon match), DELETE, SET, RETURN. Exemple : MATCH (p:Personne)-[:AMI]->(a) WHERE p.nom=''Alice'' RETURN a.nom. Idéal pour recommandation, détection de fraude, analyse de réseaux sociaux, gestion d''identité, knowledge graph.', 'Cours intégré Big Data NoSQL', 11),
  ('bigdata', 'Sharding vs réplication', 'Sharding (partitionnement horizontal) : découper un dataset en fragments (shards) répartis sur plusieurs nœuds selon une clé de partition. Objectif : scalabilité horizontale (plus de capacité de stockage et débit d''écriture). Réplication : copier les mêmes données sur plusieurs nœuds (master-slave ou multi-master). Objectif : haute disponibilité, tolérance aux pannes, scalabilité en lecture. Les deux sont complémentaires : MongoDB combine replica sets (HA) et sharding (scale). Cassandra combine partitionnement (anneau) et facteur de réplication (RF=3 typique).', 'Cours intégré Big Data NoSQL', 12),
  ('bigdata', 'ETL vs ELT et Data Lake', 'ETL (Extract-Transform-Load) : extraction depuis sources, transformation/nettoyage sur un serveur intermédiaire, puis chargement dans une cible (data warehouse). Adapté aux SGBDR traditionnels. ELT (Extract-Load-Transform) : chargement brut dans une cible scalable (data lake HDFS, S3, BigQuery, Snowflake) puis transformation à la demande grâce à la puissance de la cible. Adapté au Big Data. Data Lake : référentiel centralisé stockant des données brutes hétérogènes (vs Data Warehouse structuré). Le Data Lakehouse combine les deux paradigmes (Delta Lake, Iceberg).', 'Cours intégré Big Data NoSQL', 13),
  ('sig', 'Definition d''un SIG', 'Un SIG (Systeme d''Information Geographique) est un systeme informatique permettant l''acquisition, le stockage, le traitement et l''affichage d''informations sous forme de donnees spatiales et geographiques. C''est un outil d''aide a la decision qui revele les relations spatiales complexes.', 'Cours intégré Système d''Info Géographique', 0),
  ('sig', 'Les 5A des fonctionnalites SIG', 'Les fonctionnalites d''un SIG se resument en 5A : l''Abstraction, l''Acquisition, l''Archivage, l''Analyse et l''Affichage. Ces cinq fonctions couvrent tout le cycle de vie de la donnee geographique, de sa modelisation a sa restitution cartographique.', 'Cours intégré Système d''Info Géographique', 1),
  ('sig', 'Les 5 composants d''un SIG', 'Un SIG ne se reduit pas au logiciel : il comprend le Materiel (ordinateurs, GPS, serveurs), le Logiciel (QGIS, ArcGIS, GRASS), les Donnees (cœur du systeme : spatiales = ou ? et attributaires = quoi ?), les Personnes (techniciens, decideurs) et les Methodes (procedures et protocoles).', 'Cours intégré Système d''Info Géographique', 2),
  ('sig', 'Modele vecteur', 'Le modele vecteur represente le monde par des objets geometriques discrets : le Point (dimension nulle, ex : un arbre), la Ligne (unidimensionnel, ex : une route) et le Polygone (bidimensionnel, ex : une parcelle). Chaque entite possede une geometrie (forme) et des attributs (caracteristiques en table).', 'Cours intégré Système d''Info Géographique', 3),
  ('sig', 'Modele raster', 'Le modele raster represente le monde par une grille reguliere de cellules (pixels), chaque cellule portant une valeur representant un phenomene (altitude, temperature, occupation du sol). Il est ideal pour les donnees continues : MNT, images satellites, photographies aeriennes.', 'Cours intégré Système d''Info Géographique', 4),
  ('sig', 'Systeme de coordonnees geographiques vs projection', 'Le systeme de coordonnees geographiques repere un point par latitude et longitude (degres) sur un ellipsoide modelisant la Terre. La projection cartographique est la methode mathematique transformant la surface courbe en surface plane ; toute projection deforme au moins une propriete (surfaces, formes, distances ou angles).', 'Cours intégré Système d''Info Géographique', 5),
  ('sig', 'SRID et systemes de reference', 'Le SRID (Spatial Reference IDentifier) est l''identifiant numerique du systeme de projection d''un objet : par exemple `2154` pour le RGF93/Lambert93 (unite metre) ou EPSG:4326 pour le WGS 84 (utilise pour le Cameroun). Melanger des projections differentes provoque des superpositions incorrectes des couches.', 'Cours intégré Système d''Info Géographique', 6),
  ('sig', 'Couches (Layers)', 'Un projet SIG est constitue de multiples couches superposees, comparables a des calques transparents, chacune contenant un type d''information homogene (routes, rivieres, parcelles). Toutes les couches d''un projet doivent partager le meme systeme de coordonnees pour se superposer correctement.', 'Cours intégré Système d''Info Géographique', 7),
  ('sig', 'Analyse spatiale vecteur', 'Les operations vectorielles transforment les donnees en information : la selection par localisation (entites a l''interieur d''une zone), le Buffer ou tampon (zone d''influence autour d''une entite, ex : 100 m d''une riviere) et les operateurs Intersection, Union, Fusion combinant plusieurs couches.', 'Cours intégré Système d''Info Géographique', 8),
  ('sig', 'Analyse spatiale raster', 'Les operations raster comprennent l''algebre des cartes (combinaison mathematique de couches, ex : addition de couches de pluviometrie) et l''analyse de pente et d''orientation calculee a partir d''un Modele Numerique de Terrain (MNT).', 'Cours intégré Système d''Info Géographique', 9),
  ('sig', 'Composants d''une carte finale', 'Une carte, produit final le plus courant d''un SIG, doit etre claire, lisible et communiquer un message. Elle comprend des elements essentiels : le titre, la legende, l''echelle, la fleche nord, la source des donnees et l''auteur.', 'Cours intégré Système d''Info Géographique', 10),
  ('sig', 'SQL et ses sous-ensembles', 'SQL (Structured Query Language) manipule les donnees au sein d''un SGBDR. Il comprend trois sous-ensembles : le LDD (Langage de Definition de Donnees), le LCD (Langage de Controle de Donnees, gestion des droits) et le LMD (Langage de Manipulation de Donnees : recherche, insertion, mise a jour, suppression).', 'Cours intégré Système d''Info Géographique', 11),
  ('sig', 'Requete de selection SQL', 'La syntaxe de base est `SELECT (attributs) FROM (tables) WHERE (conditions)` : SELECT indique les colonnes a afficher, FROM les tables sources, WHERE les conditions (optionnelle). Sous PostgreSQL, les noms non proteges sont convertis en minuscules ; les majuscules exigent des guillemets doubles `"COMMUNE"`.', 'Cours intégré Système d''Info Géographique', 12),
  ('sig', 'Operateurs SQL et clause GROUP BY', 'Les operateurs de comparaison (`=`, `<>`, `BETWEEN`, `IN`, `LIKE` avec jokers `%` et `_`) et logiques (`AND`, `OR`, `NOT`) definissent la clause WHERE. `GROUP BY` regroupe les enregistrements pour les fonctions d''agregation (`count`, `sum`, `min`, `max`, `avg`), et `HAVING` filtre sur ces colonnes agregees.', 'Cours intégré Système d''Info Géographique', 13),
  ('sig', 'Extensions spatiales PostGIS et fonctions ST_', 'PostGIS ajoute a PostgreSQL des types geometriques (point, ligne, polygone) stockes en WKB/WKT et des fonctions prefixees `ST_` (standard SQL/MM) : `ST_Area()`, `ST_Perimeter()`, `ST_Buffer()`, `ST_Centroid()`, `ST_X()`/`ST_Y()`, `ST_IsValid()`, `ST_SRID()`. Les tables internes `geometry_columns` et `spatial_ref_sys` sont maintenues automatiquement.', 'Cours intégré Système d''Info Géographique', 14),
  ('sig', 'QGIS : interface et SCR', 'QGIS (version LTS 3.40) est un logiciel libre de cartographie dont l''interface comprend la barre de menu, la barre d''outils, la fenetre Legende (a gauche), la fenetre carte principale et la barre d''etat. A l''ouverture d''une couche, on choisit son SCR (Systeme de Coordonnees de Reference) ; le WGS 84 est utilise pour le Cameroun.', 'Cours intégré Système d''Info Géographique', 15),
  ('sig', 'Gestion des couches et cartographie thematique sous QGIS', 'Dans la Legende, l''ordre d''empilement se gere par glisser-deposer en placant en haut les couches ponctuelles, puis lineaires, surfaciques et enfin images. L''onglet Style permet la cartographie thematique : Symbole unique, valeur individuelle (categorise) ou Gradue selon un attribut.', 'Cours intégré Système d''Info Géographique', 16),
  ('siad', 'SIAD : definition', 'Un Systeme d''Information d''Aide a la Decision (SIAD / DSS) est un systeme interactif assistant le decideur dans des problemes semi-structures, en combinant donnees, modeles et interface. Il ne remplace pas le decideur mais l''eclaire.', 'Cours intégré SI d''Aide à la Décision', 0),
  ('siad', 'Modele de rationalite economique', 'Ce modele suppose un decideur parfaitement rationnel disposant d''informations completes, de preferences stables et capable de maximiser son utilite. Il s''oppose a la rationalite limitee (Simon) ou information et capacite cognitive sont bornees.', 'Cours intégré SI d''Aide à la Décision', 1),
  ('siad', 'Types de decisions', 'On distingue les decisions structurees (programmables, automatisables), semi-structurees (cible des SIAD) et non structurees (strategiques, jugement humain). On les classe aussi en strategiques, tactiques et operationnelles selon l''horizon.', 'Cours intégré SI d''Aide à la Décision', 2),
  ('siad', 'Loi de Pareto (80/20)', 'Loi statistique selon laquelle environ 80 % des effets proviennent de 20 % des causes. Elle aide a prioriser : on concentre l''effort sur le petit nombre de causes (les 20 %) responsables de la majorite des consequences.', 'Cours intégré SI d''Aide à la Décision', 3),
  ('siad', 'Diagramme de Pareto', 'Representation par un histogramme decroissant des causes complete d''une courbe cumulative des pourcentages. Il visualise les causes dominantes (les `vital few`) a traiter en priorite par rapport aux `trivial many`.', 'Cours intégré SI d''Aide à la Décision', 4),
  ('siad', 'Matrice d''Eisenhower', 'Outil de gestion du temps croisant deux axes (Important / Non important) x (Urgent / Non urgent), donnant 4 quadrants : Faire, Planifier, Deleguer, Eliminer. Elle hierarchise les taches pour reduire la procrastination.', 'Cours intégré SI d''Aide à la Décision', 5),
  ('siad', 'Diagramme d''Ishikawa (causes-effets)', 'Aussi appele diagramme en arete de poisson, il organise les causes d''un probleme par familles (souvent les 5M : Main-d''oeuvre, Methode, Materiel, Matiere, Milieu). Combine a Pareto, il approfondit l''analyse des causes racines.', 'Cours intégré SI d''Aide à la Décision', 6),
  ('siad', 'Matrice de decision (tableau multicritere)', 'Tableau croisant alternatives (lignes) et criteres (colonnes). Chaque critere recoit un poids, chaque alternative un score par critere ; le score pondere total designe la meilleure option. Methode d''aide a la decision multicritere.', 'Cours intégré SI d''Aide à la Décision', 7),
  ('siad', 'Methode AHP', 'L''Analytic Hierarchy Process (Saaty) pondere les criteres par comparaisons par paires sur une echelle 1-9, structurees en hierarchie. Elle calcule des priorites via les vecteurs propres et controle la coherence (ratio de coherence).', 'Cours intégré SI d''Aide à la Décision', 8),
  ('siad', 'Normalisation des scores', 'Pour comparer des criteres d''echelles differentes, on convertit les scores en valeurs comprises entre 0 et 1 (ex. min-max). Cela rend les criteres homogenes avant ponderation et agregation dans la matrice de decision.', 'Cours intégré SI d''Aide à la Décision', 9),
  ('siad', 'Analyse SWOT', 'Outil strategique recensant Forces, Faiblesses (interne), Opportunites et Menaces (externe). Il aide au diagnostic prealable a la decision strategique en croisant capacites internes et environnement.', 'Cours intégré SI d''Aide à la Décision', 10),
  ('siad', 'Analyse PESTEL', 'Cadre d''analyse de l''environnement macro selon 6 dimensions : Politique, Economique, Sociologique, Technologique, Ecologique, Legal. Il identifie les facteurs externes influencant la decision strategique.', 'Cours intégré SI d''Aide à la Décision', 11),
  ('siad', 'Diagramme de Gantt', 'Outil de planification de projet representant les taches en barres horizontales le long d''un axe temporel, montrant durees, jalons et dependances. Il sert au pilotage et au suivi, non a la ponderation de criteres.', 'Cours intégré SI d''Aide à la Décision', 12),
  ('siad', 'Process de prise de decision', 'Le modele de Simon decrit 3 a 4 phases : Intelligence (identifier le probleme), Design/Conception (generer les alternatives), Choix (selectionner via criteres) et Implementation/Controle (executer et evaluer).', 'Cours intégré SI d''Aide à la Décision', 13),
  ('j2e', 'Architecture multi-tiers Java EE', 'Java EE/Jakarta EE structure une application en couches: client (tier presentation), tier web (Servlets/JSP/JSF), tier metier (EJB/CDI) et tier EIS/donnees (JPA/JDBC). Cette separation favorise scalabilite, maintenabilite et reutilisation.', 'Cours intégré Programmation J2E', 0),
  ('j2e', 'Conteneurs et services', 'Un conteneur (web ou EJB) heberge les composants et fournit des services transverses: cycle de vie, injection de dependances, transactions, securite, concurrence et nommage JNDI. Le developpeur se concentre sur la logique metier, le conteneur gere l''infrastructure.', 'Cours intégré Programmation J2E', 1),
  ('j2e', 'Servlet et cycle de vie', 'Une Servlet est un composant Java cote serveur qui traite des requetes HTTP. Son cycle de vie est gere par le conteneur: `init()` une seule fois au chargement, `service()` (puis `doGet`/`doPost`) a chaque requete, et `destroy()` au dechargement.', 'Cours intégré Programmation J2E', 2),
  ('j2e', 'doGet vs doPost', '`doGet()` traite les requetes GET (parametres dans l''URL, idempotente, cacheable, limitee en taille); `doPost()` traite les requetes POST (donnees dans le corps, non idempotente, adaptee aux formulaires et donnees sensibles). Toutes deux recoivent `HttpServletRequest` et `HttpServletResponse`.', 'Cours intégré Programmation J2E', 3),
  ('j2e', 'JSP (JavaServer Pages)', 'JSP permet d''ecrire des pages dynamiques mélant HTML et code Java. Une JSP est compilee en Servlet par le conteneur. On privilegie EL (`${...}`) et JSTL (`<c:forEach>`, `<c:if>`) plutot que les scriptlets `<% %>` pour separer presentation et logique.', 'Cours intégré Programmation J2E', 4),
  ('j2e', 'JSF (JavaServer Faces)', 'JSF est un framework MVC oriente composants pour construire des interfaces web. Il repose sur des managed beans, un arbre de composants UI, le langage d''expression et un cycle de vie en 6 phases (Restore View, Apply Request Values, Process Validations, Update Model, Invoke Application, Render Response).', 'Cours intégré Programmation J2E', 5),
  ('j2e', 'JDBC', 'JDBC (Java Database Connectivity) est l''API bas niveau d''acces aux bases relationnelles. Le flux type: `DriverManager`/`DataSource` -> `Connection` -> `PreparedStatement` (parametre, anti-injection SQL) -> `ResultSet` -> fermeture des ressources (try-with-resources).', 'Cours intégré Programmation J2E', 6),
  ('j2e', 'JPA et ORM', 'JPA (Jakarta Persistence API) est la specification de mapping objet-relationnel; Hibernate en est l''implementation la plus repandue. Elle mappe des entites Java vers des tables et evite l''ecriture manuelle du SQL CRUD.', 'Cours intégré Programmation J2E', 7),
  ('j2e', 'Entites JPA', 'Une entite est une classe annotee `@Entity` avec une cle primaire `@Id` (souvent `@GeneratedValue`). Les associations se declarent via `@OneToMany`, `@ManyToOne`, `@OneToOne`, `@ManyToMany`, et le mapping de colonnes via `@Column`, `@Table`, `@JoinColumn`.', 'Cours intégré Programmation J2E', 8),
  ('j2e', 'EntityManager', 'L''`EntityManager` est l''interface centrale de JPA: il gere le cycle de vie des entites (`persist`, `merge`, `remove`, `find`) et le contexte de persistance. Les requetes se font en JPQL via `createQuery` ou avec l''API Criteria, dans le cadre d''une transaction.', 'Cours intégré Programmation J2E', 9),
  ('j2e', 'EJB (Enterprise JavaBeans)', 'Les EJB sont des composants metier transactionnels geres par le conteneur. On distingue les Session Beans `@Stateless` (sans etat, mutualises), `@Stateful` (etat par client) et `@Singleton` (instance unique), avec gestion automatique des transactions et de la securite.', 'Cours intégré Programmation J2E', 10),
  ('j2e', 'Modele MVC', 'Le pattern MVC separe Modele (donnees/entites JPA), Vue (JSP/JSF) et Controleur (Servlet ou managed bean). En Java EE le ''Model 2'' utilise une Servlet comme controleur frontal qui delegue la logique aux EJB et choisit la vue JSP a afficher.', 'Cours intégré Programmation J2E', 11),
  ('j2e', 'Sessions et suivi d''etat', 'HTTP etant sans etat, le suivi de session utilise `HttpSession` (via `request.getSession()`), generalement implementee par un cookie `JSESSIONID` ou la reecriture d''URL. On y stocke des attributs propres a l''utilisateur (panier, identite) entre les requetes.', 'Cours intégré Programmation J2E', 12),
  ('j2e', 'Deploiement et serveurs', 'Une application web Java EE se package en archive `WAR` (et un module EE complet en `EAR`). Elle se deploie sur un conteneur web comme Tomcat (Servlet/JSP) ou un serveur d''applications complet comme GlassFish/WildFly/Payara (qui ajoute EJB, JMS, JTA).', 'Cours intégré Programmation J2E', 13),
  ('j2e', 'Descripteur web.xml et annotations', 'Le deploiement web se configure via `web.xml` (mapping de servlets, filtres, parametres) ou via les annotations equivalentes `@WebServlet`, `@WebFilter`, `@WebListener`. Depuis Servlet 3.0, le `web.xml` est devenu optionnel grace aux annotations.', 'Cours intégré Programmation J2E', 14),
  ('python', 'Origine et nature de Python', 'Python est un langage cree en 1990 par Guido van Rossum, libre (licence gratuite), portable (independant de l''OS) et interprete. Sa syntaxe lisible le rend adapte aussi bien aux debutants qu''aux experts (web, data science, automatisation).', 'Cours intégré Python Avancée', 0),
  ('python', 'Execution et REPL', 'On execute du code soit interactivement dans l''interpreteur (chevrons `>>>`) via la commande `python` (ou `py`/`python3`), soit en lancant un script avec `python mon_fichier.py`. Sous Windows il faut cocher "Add to PATH" a l''installation.', 'Cours intégré Python Avancée', 1),
  ('python', 'Variables et affectation', 'Une variable est un nom associe a une valeur, declaree par l''operateur d''affectation `=`, par exemple `livre = "Gatsby le Magnifique"`. La reassignation reutilise simplement `=`. Une variable possede trois elements : son nom, son type et sa valeur.', 'Cours intégré Python Avancée', 2),
  ('python', 'Conventions de nommage (PEP8)', 'Les noms doivent etre descriptifs, en mots complets, sans accents, commencant par une lettre ou un underscore, et suivre le snake_case (`revenu_annuel`). Les noms sont sensibles a la casse : `age`, `Age` et `AGE` sont trois variables differentes.', 'Cours intégré Python Avancée', 3),
  ('python', 'Types de donnees primitifs', 'Les types primitifs sont les entiers (`int`), les flottants (`float`, decimale notee avec un point : `3.14`), les chaines (`str`) et les booleens (`bool`). La fonction `type()` renvoie le type d''un objet, utile pour verifier la nature d''une valeur.', 'Cours intégré Python Avancée', 4),
  ('python', 'Operateurs arithmetiques', 'Python supporte `+` (somme), `-` (difference), `*` (produit), `/` (quotient, toujours float), `%` (reste/modulo). Il existe aussi `//` (division entiere) et `**` (puissance). L''interpreteur peut servir de calculatrice : `(100 + 81) * 11` donne `1991`.', 'Cours intégré Python Avancée', 5),
  ('python', 'Chaines de caracteres', 'Une chaine est du texte entoure de guillemets simples ou doubles (`''bonjour''` ou `"bonjour"`). `''912''` est une chaine alors que `912` est un entier. Les chaines sont immuables : elles ne peuvent pas etre modifiees apres creation.', 'Cours intégré Python Avancée', 6),
  ('python', 'f-strings (formatage)', 'Une f-string est une chaine prefixee par `f` contenant des expressions entre accolades `{}` evaluees a l''execution, par exemple `f"Je m''appelle {prenom} et j''ai {age} ans"`. C''est le moyen recommande pour inserer des variables dans du texte.', 'Cours intégré Python Avancée', 7),
  ('python', 'Listes : creation et indexation', 'Une liste, notee entre crochets `[ ]`, stocke une collection ordonnee et modifiable d''elements de types quelconques. L''indexation commence a 0 (`liste[0]` premier element) et accepte les indices negatifs (`liste[-1]` dernier element).', 'Cours intégré Python Avancée', 8),
  ('python', 'Methodes de liste', 'Les listes offrent `append()` (ajout en fin), `remove()` (retire la 1re occurrence), `sort()` (tri), `extend()`, `insert()`, `pop()`, `index()`, `count()`, `reverse()`. La fonction `len()` donne la taille ; un indice >= a la taille leve une `IndexError`.', 'Cours intégré Python Avancée', 9),
  ('python', 'Tuples et immutabilite', 'Un tuple, note entre parentheses `( )`, partage l''indexation des listes mais est immuable : ses elements ne peuvent pas etre modifies apres creation. On l''utilise pour des donnees fixes (coordonnees, enregistrements constants).', 'Cours intégré Python Avancée', 10),
  ('python', 'Operateur d''appartenance in', 'L''operateur `in` teste l''appartenance d''un element a une sequence (liste, tuple, chaine) et renvoie `True` ou `False`. Exemple : `"a" in "chat"` vaut `True`. Il sert aussi a iterer dans une boucle `for x in sequence`.', 'Cours intégré Python Avancée', 11),
  ('python', 'Indexation des chaines comme listes', 'Une chaine se comporte comme une liste de caracteres : chaque caractere possede un indice de 0 a la longueur moins un. Pour `langage = "PYTHON"`, `langage[2]` renvoie `"T"` et l''indice negatif `langage[-4]` renvoie egalement `"T"`.', 'Cours intégré Python Avancée', 12),
  ('oracle', 'Instance Oracle', 'Une instance Oracle est l''ensemble des structures mémoire (la SGA) et des processus d''arrière-plan (DBWR, LGWR, SMON, PMON, CKPT...) qui s''exécutent en RAM. Elle est distincte de la base de données (les fichiers sur disque) : une instance pilote une base, et c''est le couple instance + base qui forme un serveur Oracle opérationnel.', 'Cours intégré Administration BD Oracle', 0),
  ('oracle', 'SGA (System Global Area)', 'La SGA est une zone mémoire partagée par tous les processus de l''instance, allouée au démarrage. Ses composants principaux sont le `Database Buffer Cache` (blocs de données), le `Shared Pool` (Library Cache + Data Dictionary Cache) et le `Redo Log Buffer` (vecteurs de reprise avant écriture dans les redo logs).', 'Cours intégré Administration BD Oracle', 1),
  ('oracle', 'PGA (Program Global Area)', 'La PGA est une zone mémoire privée, propre à chaque processus serveur/utilisateur, non partagée. Elle contient la zone de tri, les informations de session et l''état du curseur. Sa taille n''a aucun lien avec les arguments INITIAL/NEXT/MINEXTENTS de CREATE TABLESPACE qui concernent l''allocation disque des extents.', 'Cours intégré Administration BD Oracle', 2),
  ('oracle', 'Processus d''arriere-plan', 'Ce sont les processus système de l''instance : `DBWR` (écrit les blocs modifiés du buffer cache vers les datafiles), `LGWR` (écrit le redo log buffer vers les fichiers redo), `SMON` (reprise d''instance, défragmentation), `PMON` (nettoie les processus utilisateur défaillants, libère les ressources) et `CKPT` (déclenche les points de reprise / checkpoints).', 'Cours intégré Administration BD Oracle', 3),
  ('oracle', 'DBWR et LGWR', '`DBWR` (Database Writer) écrit asynchroniquement les blocs sales (dirty buffers) du Database Buffer Cache vers les datafiles. `LGWR` (Log Writer) écrit séquentiellement le contenu du Redo Log Buffer dans les fichiers redo log à chaque COMMIT, à chaque remplissage du tiers du buffer ou toutes les 3 secondes (write-ahead logging).', 'Cours intégré Administration BD Oracle', 4),
  ('oracle', 'SMON, PMON et CKPT', '`SMON` effectue la récupération automatique de l''instance au redémarrage (instance recovery) et coalesce les espaces libres. `PMON` détecte et nettoie les processus utilisateur morts (rollback, libération de verrous). `CKPT` met à jour les en-têtes des datafiles et le fichier de contrôle lors d''un checkpoint pour synchroniser SGA et disque.', 'Cours intégré Administration BD Oracle', 5),
  ('oracle', 'Fichiers de la base de donnees', 'Une base Oracle repose sur trois types de fichiers physiques : les `datafiles` (données et index réels), les `control files` (métadonnées sur la structure de la base : noms/emplacements des fichiers, SCN, informations RMAN) et les `redo log files` (journalisation de toutes les modifications, indispensables à la reprise).', 'Cours intégré Administration BD Oracle', 6),
  ('oracle', 'Tablespaces et segments', 'Un `tablespace` est une unité logique de stockage qui regroupe un ou plusieurs datafiles. Le tablespace `SYSTEM` contient obligatoirement le dictionnaire de données (data dictionary) et ne peut être supprimé. La hiérarchie logique est : tablespace → segment (table, index) → extent (extent) → bloc Oracle (plus petite unité d''E/S).', 'Cours intégré Administration BD Oracle', 7),
  ('oracle', 'Demarrage de l''instance (NOMOUNT / MOUNT / OPEN)', 'Le démarrage suit trois phases : `STARTUP NOMOUNT` lit le fichier de paramètres et alloue la SGA + démarre les processus (instance seule) ; `MOUNT` lit le fichier de contrôle et associe la base ; `OPEN` ouvre les datafiles et redo logs, rendant la base accessible aux utilisateurs. `SHUTDOWN` parcourt l''inverse.', 'Cours intégré Administration BD Oracle', 8),
  ('oracle', 'Mode ARCHIVELOG et RMAN', 'En mode `ARCHIVELOG`, le processus ARCn archive chaque redo log rempli avant réécriture, permettant la récupération jusqu''à un instant précis (point-in-time recovery). `RMAN` (Recovery Manager) est l''outil Oracle de sauvegarde/restauration : sauvegardes complètes, incrémentielles, validation des blocs et catalogue de récupération.', 'Cours intégré Administration BD Oracle', 9),
  ('oracle', 'PL/SQL', '`PL/SQL` est l''extension procédurale d''Oracle au langage SQL : il ajoute variables, structures de contrôle (IF, LOOP), curseurs, gestion d''exceptions et blocs nommés. Un bloc se structure en sections `DECLARE` / `BEGIN` / `EXCEPTION` / `END;` et permet d''écrire procédures stockées, fonctions, packages et triggers exécutés côté serveur.', 'Cours intégré Administration BD Oracle', 10),
  ('oracle', 'Utilisateurs, privileges et roles', 'Oracle gère la sécurité via des `utilisateurs` (schémas), des `privilèges` système (CREATE SESSION, CREATE TABLE) ou objet (SELECT, UPDATE sur une table), accordés par `GRANT` et retirés par `REVOKE`. Un `rôle` regroupe un ensemble de privilèges pour les attribuer en bloc (ex. rôles prédéfinis CONNECT, RESOURCE, DBA).', 'Cours intégré Administration BD Oracle', 11),
  ('oracle', 'SQL*Plus et outils d''administration', '`SQL*Plus` est l''interface ligne de commande historique pour se connecter à Oracle et exécuter SQL/PL/SQL. Les principaux outils d''administration sont `Oracle Enterprise Manager` (OEM, console graphique), `SQL Developer` (IDE graphique) et `SQL*Plus`. C''est par SQL*Plus connecté SYSDBA qu''on lance STARTUP/SHUTDOWN.', 'Cours intégré Administration BD Oracle', 12),
  ('oracle', 'Operateurs d''ensemble', 'Les opérateurs d''ensemble combinent les résultats de deux requêtes SELECT compatibles en projection : `UNION` (fusion sans doublons), `UNION ALL` (fusion avec doublons), `INTERSECT` (lignes communes aux deux ensembles) et `MINUS` (lignes du premier absent du second). Ils exigent le même nombre de colonnes et des types compatibles.', 'Cours intégré Administration BD Oracle', 13),
  ('oracle', 'GROUP BY, ROLLUP et CUBE', '`GROUP BY` regroupe les lignes pour appliquer des fonctions d''agrégation. `ROLLUP(a,b)` produit en plus des sous-totaux hiérarchiques et un total général (agrégation en cascade de droite à gauche). `CUBE(a,b)` génère tous les sous-totaux de toutes les combinaisons possibles de colonnes, donnant un tableau croisé multidimensionnel complet.', 'Cours intégré Administration BD Oracle', 14),
  ('sqlserver', 'Architecture client-serveur SQL Server', 'Microsoft SQL Server est un SGBDR client-serveur dont le moteur relationnel (Database Engine) traite les requêtes T-SQL via le protocole `TDS` (Tabular Data Stream). Une instance est une copie isolée du moteur, identifiée par défaut par le nom de la machine ou nommée (`MACHINE\INSTANCE`), avec son propre jeu de bases système, ports et services.', 'Cours intégré Administration BD SQL-Server', 0),
  ('sqlserver', 'Bases de données système', '`master` stocke la configuration serveur, les logins et les métadonnées de toutes les bases ; `model` est le gabarit copié à chaque `CREATE DATABASE` ; `msdb` héberge SQL Server Agent (jobs, alertes, historique de sauvegarde) ; `tempdb` est recréée à chaque démarrage et sert aux objets temporaires et au tri.', 'Cours intégré Administration BD SQL-Server', 1),
  ('sqlserver', 'Fichiers d''une base (.mdf/.ndf/.ldf)', 'Une base comporte un fichier de données primaire `.mdf` (obligatoire, un seul), des fichiers secondaires `.ndf` (optionnels, pour répartir les données sur plusieurs disques/groupes de fichiers) et au moins un fichier journal `.ldf` qui enregistre toutes les transactions pour la récupération.', 'Cours intégré Administration BD SQL-Server', 2),
  ('sqlserver', 'Transact-SQL (T-SQL)', '`Transact-SQL` est l''extension procédurale propriétaire de SQL par Microsoft. Elle ajoute au SQL standard les variables (`DECLARE`), le contrôle de flux (`IF`, `WHILE`, `TRY...CATCH`), les fonctions intégrées, les procédures stockées, les déclencheurs et la gestion explicite des transactions.', 'Cours intégré Administration BD SQL-Server', 3),
  ('sqlserver', 'DDL, DML, DCL, TCL', 'Le T-SQL se décline en DDL (structure : `CREATE`, `ALTER`, `DROP`), DML (données : `SELECT`, `INSERT`, `UPDATE`, `DELETE`), DCL (droits : `GRANT`, `REVOKE`, `DENY`) et TCL (transactions : `BEGIN TRAN`, `COMMIT`, `ROLLBACK`).', 'Cours intégré Administration BD SQL-Server', 4),
  ('sqlserver', 'DROP vs DELETE vs TRUNCATE', '`DELETE` (DML) supprime des lignes selon un `WHERE`, est journalisé ligne à ligne et déclenche les triggers ; `DROP` (DDL) supprime intégralement l''objet (table, structure et données) ; `TRUNCATE` vide une table en désallouant les pages, sans `WHERE`, non journalisé ligne à ligne et réinitialise l''`IDENTITY`.', 'Cours intégré Administration BD SQL-Server', 5),
  ('sqlserver', 'Composants de la suite SQL Server', 'Au-delà du moteur de base de données : `SSIS` (Integration Services, ETL Extract-Transform-Load), `SSAS` (Analysis Services, cubes OLAP et data mining), `SSRS` (Reporting Services, états/rapports), interrogés en `MDX`/`DAX`, plus les outils `SSMS`, `SQL Server Profiler`, `sqlcmd` et l''Assistant de paramétrage du moteur de base de données.', 'Cours intégré Administration BD SQL-Server', 6),
  ('sqlserver', 'OLTP vs OLAP', 'Un serveur OLTP (transactionnel) gère de nombreuses petites transactions concurrentes en lecture/écriture sur un schéma normalisé, optimisé pour l''intégrité et le temps de réponse. Un serveur OLAP (analytique, ex. SSAS) agrège de gros volumes historiques dénormalisés (étoile/flocon) pour l''aide à la décision, en lecture quasi exclusive.', 'Cours intégré Administration BD SQL-Server', 7),
  ('sqlserver', 'SSMS et SQL Server Profiler', '`SSMS` (SQL Server Management Studio) est l''environnement graphique d''administration et d''écriture de requêtes. `SQL Server Profiler` capture et trace en temps réel les événements du serveur (requêtes, connexions, deadlocks) ; cette trace, persistée dans un fichier `.trc`, fait office de journal d''audit/diagnostic des activités.', 'Cours intégré Administration BD SQL-Server', 8),
  ('sqlserver', 'Sécurité : logins, users, rôles, schémas', 'Un `login` (niveau serveur, stocké dans `master`) authentifie une connexion ; un `user` (niveau base) lui est mappé pour autoriser l''accès à une base. Les permissions s''octroient via des rôles serveur (`sysadmin`) et de base (`db_owner`, `db_datareader`). Un `schema` est un conteneur de noms d''objets servant aussi d''unité de gestion des droits.', 'Cours intégré Administration BD SQL-Server', 9),
  ('sqlserver', 'SGBD multi-bases et multi-schémas', 'Une même instance SQL Server héberge plusieurs bases de données indépendantes (multi-bases). Au sein de chaque base, les objets sont organisés en plusieurs schémas (`dbo`, `ventes`, ...), namespaces logiques qui isolent et sécurisent les objets : SQL Server est donc multi-base ET multi-schéma.', 'Cours intégré Administration BD SQL-Server', 10),
  ('sqlserver', 'Sauvegardes : full, differential, log', '`BACKUP DATABASE` complète copie toute la base ; la sauvegarde différentielle ne copie que les pages modifiées depuis la dernière complète (base = dernière full) ; `BACKUP LOG` copie le journal des transactions (mode FULL/BULK_LOGGED) et permet une restauration à un instant précis (`point-in-time`).', 'Cours intégré Administration BD SQL-Server', 11),
  ('sqlserver', 'Restauration et RESTORE', 'La restauration applique `RESTORE DATABASE ... WITH NORECOVERY` pour la full, puis la différentielle, puis les logs dans l''ordre, et enfin `WITH RECOVERY` (ou `STOPAT`) pour rendre la base accessible. La restauration complète remplace toute la base ; la différentielle nécessite d''abord la full de base correspondante.', 'Cours intégré Administration BD SQL-Server', 12),
  ('sqlserver', 'Index clustered et non-clustered', 'L''index `CLUSTERED` ordonne physiquement les lignes selon la clé (un seul par table, souvent la clé primaire) : les pages de données sont les feuilles. L''index `NONCLUSTERED` est une structure séparée (B-tree) dont les feuilles pointent vers les lignes ; on peut en créer plusieurs pour accélérer les recherches sur d''autres colonnes.', 'Cours intégré Administration BD SQL-Server', 13),
  ('sqlserver', 'SQL Server Agent et jobs', '`SQL Server Agent` est le service de planification stocké dans `msdb`. Il exécute des `jobs` (tâches T-SQL, SSIS, scripts) selon des `schedules`, déclenche des `alerts` et envoie des notifications par `operators`, automatisant sauvegardes, réindexations et maintenance.', 'Cours intégré Administration BD SQL-Server', 14),
  ('sqlserver', 'Contraintes et intégrité', 'L''intégrité est garantie par des contraintes : `PRIMARY KEY` (identité unique non nulle), `FOREIGN KEY` (intégrité référentielle), `UNIQUE`, `NOT NULL`, `CHECK` (règle de validation) et `DEFAULT`. Elles s''ajoutent en DDL (`ALTER TABLE ... ADD CONSTRAINT`) et le moteur les vérifie à chaque modification.', 'Cours intégré Administration BD SQL-Server', 15),
  ('sqlserver', 'Déclencheurs (triggers) et procédures stockées', 'Une procédure stockée est un bloc T-SQL nommé et précompilé exécuté par `EXEC`. Un `trigger` est une procédure liée à une table, déclenchée automatiquement sur `INSERT`/`UPDATE`/`DELETE` (tables logiques `inserted`/`deleted`) ; il sert à maintenir des règles métier, par ex. décrémenter les places disponibles d''une table de mariage.', 'Cours intégré Administration BD SQL-Server', 16),
  ('sqlserver', 'BULK INSERT, BCP et chargement de masse', '`BULK INSERT` est une commande T-SQL qui charge un fichier de données dans une table depuis l''intérieur du serveur. `bcp` (Bulk Copy Program) est un utilitaire en ligne de commande externe qui importe ET exporte des données entre un fichier et une table, scriptable hors SSMS.', 'Cours intégré Administration BD SQL-Server', 17),
  ('techcom', 'Definition de la communication', 'La communication est le processus de transmission d''un message d''un emetteur vers un recepteur via un canal, dans le but de produire une comprehension partagee et eventuellement un changement de comportement. Elle repose sur le decodage correct du message et la presence d''un retour (feedback).', 'Cours intégré Techniques de Communication', 0),
  ('techcom', 'Schema de Shannon-Weaver', 'Le modele canonique comporte sept elements : emetteur (source), message (information codee), canal (support de transmission), recepteur (destinataire), feedback (retour), bruit (perturbation) et contexte (situation). Le codage et le decodage assurent la mise en forme et l''interpretation du message.', 'Cours intégré Techniques de Communication', 1),
  ('techcom', 'Communication verbale vs non-verbale', 'La communication verbale utilise les mots (oral ou ecrit) ; la communication non-verbale passe par les gestes, postures, expressions du visage, regard, ton et silence. Le non-verbal accompagne, renforce ou contredit le verbal et porte une part importante du sens emotionnel.', 'Cours intégré Techniques de Communication', 2),
  ('techcom', 'Ecoute active', 'L''ecoute active consiste a comprendre reellement le message de l''interlocuteur avant de repondre, en se concentrant sur lui, en reformulant, en questionnant et en evitant de juger ou d''interrompre. Son objectif principal est de comprendre le message pour etablir une relation de confiance.', 'Cours intégré Techniques de Communication', 3),
  ('techcom', 'Communication interpersonnelle', 'Echange direct entre deux personnes (ou en petit groupe) en presence ou a distance. Elle se caracterise par l''immediatete du feedback, l''importance du non-verbal et l''adaptation au contexte relationnel des interlocuteurs.', 'Cours intégré Techniques de Communication', 4),
  ('techcom', 'Communication institutionnelle / corporate', 'La communication institutionnelle vise a promouvoir l''image, l''identite et la notoriete globale de l''entreprise (et non un produit precis) aupres de ses publics : valeurs, mission, responsabilite. Elle cible salaries, partenaires, medias, pouvoirs publics et grand public.', 'Cours intégré Techniques de Communication', 5),
  ('techcom', 'Communication marketing', 'La communication marketing a pour but de promouvoir un produit ou un service et d''influencer l''acte d''achat (publicite, promotion, marketing direct, communication digitale). Elle s''adresse aux clients et prospects et soutient les ventes et la differenciation face a la concurrence.', 'Cours intégré Techniques de Communication', 6),
  ('techcom', 'Communication interne vs externe', 'La communication interne s''adresse aux membres de l''entreprise (salaries, services) pour informer, motiver et federer ; la communication externe vise les publics exterieurs (clients, fournisseurs, medias, partenaires) pour vendre, informer et construire l''image. Toutes deux sont indispensables a la competitivite.', 'Cours intégré Techniques de Communication', 7),
  ('techcom', 'Communication electronique et Web 2.0', 'La communication electronique exploite les TIC et le Web 2.0 (site web, e-mailing, reseaux sociaux, blog, newsletter, podcast) pour diffuser l''information de maniere interactive, rapide et a faible cout. Elle augmente la visibilite, la reactivite et la notoriete de l''entreprise.', 'Cours intégré Techniques de Communication', 8),
  ('techcom', 'Objectifs cognitif, affectif et conatif', 'Une action de communication poursuit trois types d''objectifs : cognitif (faire connaitre, informer), affectif (faire aimer, creer une attitude favorable) et conatif (faire agir, declencher l''achat ou le comportement). Ils correspondent aux etapes du modele AIDA : Attention, Interet, Desir, Action.', 'Cours intégré Techniques de Communication', 9),
  ('techcom', 'Plan de communication', 'Document qui englobe toutes les actions necessaires pour guider la strategie de communication d''une entreprise. Ses etapes : analyser le contexte global, fixer les objectifs (strategie), determiner les cibles, definir les messages, choisir les outils/medias, puis elaborer et evaluer le plan.', 'Cours intégré Techniques de Communication', 10),
  ('techcom', 'Freins et obstacles a la communication', 'Les freins (bruits) peuvent etre techniques (canal defaillant), semantiques (vocabulaire mal compris), psychologiques (prejuges, emotions, stress), culturels ou organisationnels. Ils alterent le message ; on les reduit par la reformulation, la clarte, l''ecoute et le feedback.', 'Cours intégré Techniques de Communication', 11),
  ('techcom', 'Redaction administrative et professionnelle', 'La redaction administrative repond a des regles de clarte, concision, objectivite, courtoisie et respect des conventions de presentation. Elle privilegie un style neutre et precis ; ses ecrits types sont la lettre, la note de service, le compte rendu et le rapport.', 'Cours intégré Techniques de Communication', 12),
  ('techcom', 'Correspondance administrative', 'Une correspondance administrative comporte des elements normalises : en-tete (timbre/expediteur), references, objet, formule d''appel, corps du message structure, formule de politesse, signature et eventuelles pieces jointes. La lettre administrative entre services est impersonnelle, la lettre a caractere personnel s''adresse a un individu.', 'Cours intégré Techniques de Communication', 13),
  ('techcom', 'Prise de parole en public', 'La prise de parole efficace exige preparation (plan, message cle), maitrise du non-verbal (posture, regard, voix), gestion du trac et adaptation a l''auditoire. La structure type suit l''accroche, le developpement argumente et la conclusion percutante.', 'Cours intégré Techniques de Communication', 14),
  ('techcom', 'La reunion', 'Outil de communication interne collectif. Une reunion efficace requiert un ordre du jour, un animateur, un secretaire, un objectif clair, une duree maitrisee et un compte rendu diffuse. On distingue reunions d''information, de decision, de resolution de probleme et de brainstorming.', 'Cours intégré Techniques de Communication', 15),
  ('techcom', 'La contrefacon', 'La contrefacon est la reproduction ou imitation frauduleuse d''une marque, d''un produit ou d''une creation protegee, portant atteinte aux droits de propriete intellectuelle. On la combat par le depot de marque, la sensibilisation des consommateurs, les controles douaniers et les poursuites judiciaires.', 'Cours intégré Techniques de Communication', 16),
  ('entreprenariat', 'Entrepreneur', 'Personne (ou groupe) qui cree, developpe et implante une entreprise dont elle assume les risques, en mobilisant des moyens financiers, humains et materiels pour realiser un profit (Larousse). C''est celui qui poursuit inlassablement une occasion d''affaire au-dela des ressources qu''il controle deja.', 'Cours intégré Entreprenariat', 0),
  ('entreprenariat', 'Entreprise', 'Entite economique et juridiquement autonome, organisee, comprenant une ou plusieurs personnes qui combinent les facteurs de production (travail et capital) pour produire des biens ou services vendus sur un marche afin de satisfaire des besoins et degager un profit.', 'Cours intégré Entreprenariat', 1),
  ('entreprenariat', 'Entrepreneuriat (3 finalites)', 'Action de creer de la richesse et/ou de l''emploi par la creation ou la reprise d''une entreprise. Selon l''OCDE, c''est une action dynamique humaine visant a generer de la valeur par la creation/expansion d''activites economiques et l''exploitation de nouveaux produits, processus ou marches.', 'Cours intégré Entreprenariat', 2),
  ('entreprenariat', 'Esprit d''entreprendre', 'Etat d''esprit traduisant une orientation forte vers la recherche d''opportunites, la prise de risques et les initiatives creatrices de valeur. Il valorise l''imagination, l''adaptabilite, l''acceptation du risque et l''engagement personnel, y compris au sein d''organisations existantes.', 'Cours intégré Entreprenariat', 3),
  ('entreprenariat', 'Formes d''entrepreneuriat', 'On distingue quatre origines de la creation : la creation `ex-nihilo` (a partir de rien, risque maximal), la creation par `essaimage` (avec l''appui de son employeur), la creation par `franchise` (franchiseur/franchise, accompagnement payant) et la `reprise d''entreprise` (saine ou en difficulte, risque moindre).', 'Cours intégré Entreprenariat', 4),
  ('entreprenariat', 'Intrapreneuriat', 'Processus par lequel un individu (ou groupe), en association avec une organisation existante, cree une nouvelle activite ou genere le renouvellement/l''innovation au sein de cette organisation (Sharma et Chrisman, 1999). L''intrapreneur reste un salarie soumis a des obligations contractuelles envers son employeur.', 'Cours intégré Entreprenariat', 5),
  ('entreprenariat', 'Innerpreneuriat', 'Du latin ''inne'' (dedans) : l''innerpreneur tire sa motivation de lui-meme et d''une cause profonde plutot que du marche. Mu par une raison d''etre, il vise l''impact et l''accomplissement plus que la performance. Exemples : Y. Chouinard (Patagonia), S. Jobs (Apple), O. Winfrey, B. Mycoskie (TOMS).', 'Cours intégré Entreprenariat', 6),
  ('entreprenariat', 'Theories economiques de l''entrepreneur', 'Cantillon (1725) : preneur de risque dans l''incertitude (achat a prix certain, revente a prix incertain). J.-B. Say : coordinateur qui combine les facteurs de production. Schumpeter (1934) : innovateur moteur de la `destruction creatrice`. Marshall : assimile l''entrepreneur au manager. Marx : analyse l''exploitation capital/travail.', 'Cours intégré Entreprenariat', 7),
  ('entreprenariat', 'Innovation et destruction creatrice', 'Concept de Schumpeter : l''innovation (bien nouveau, methode de production, debouche, matiere premiere, organisation nouvelle) rend obsolete l''ancien et renouvelle le systeme economique. L''entrepreneur-innovateur, moteur du developpement, identifie les opportunites que les acteurs en place ne voient pas.', 'Cours intégré Entreprenariat', 8),
  ('entreprenariat', 'Environnement de l''entreprise', 'Ensemble des facteurs externes influencant l''entreprise. On distingue le `macro-environnement` (politique, juridique, economique, socioculturel : facteurs subis), le `micro-environnement` (clients, fournisseurs, concurrents, distributeurs : parties prenantes) et le `meso-environnement` (intensite concurrentielle du secteur, modele des 5+1 forces de Porter).', 'Cours intégré Entreprenariat', 9),
  ('entreprenariat', 'Classification des entreprises', 'Selon la taille (TPE 0-9, PE 10-49, ME 50-199, GE 200+ salaries ; aussi CA et capital investi), le secteur d''activite (primaire, secondaire, tertiaire, quaternaire/information) et la forme juridique. Au Cameroun, 99% des ~94 000 entreprises sont des PME et le secteur informel reste dominant.', 'Cours intégré Entreprenariat', 10),
  ('entreprenariat', 'Etapes de la creation d''entreprise', 'Cinq grandes etapes : (1) evaluation de l''opportunite ; (2) conception et formulation du projet (etudes de marche, juridique, financiere) ; (3) montage juridique et scenarios de financement/rentabilite ; (4) prise de decision ; (5) lancement de l''activite. La gestion de projet repose sur le `triangle d''or` cout-delai-performance.', 'Cours intégré Entreprenariat', 11),
  ('entreprenariat', 'Formalites de creation au Cameroun (OHADA)', 'Les formalites se font au `CFCE` (Centre de Formalites de Creation d''Entreprise) de Yaounde. Cout indicatif : 21 500 FCFA d''immatriculation au RCCM + 20 000 FCFA de droits fixes d''enregistrement ; delai de 3 a 7 jours. Formes OHADA : EURL/SASU, SARL (2-9 associes), SA/SPA (10+), SNC, GIC ; les societes morales se creent chez un notaire.', 'Cours intégré Entreprenariat', 12),
  ('entreprenariat', 'Business plan', 'Document ecrit (plan d''affaires) formalisant un projet de creation, reprise ou modification d''activite. Il comporte un volet redactionnel (idee, marche, concurrence, positionnement, cadre juridique) et un volet financier (compte previsionnel, bilan previsionnel, plan de financement, tresorerie, BFR, CAF). Sa vocation est argumentaire : convaincre banquiers et investisseurs.', 'Cours intégré Entreprenariat', 13),
  ('entreprenariat', 'Management des organisations', 'Ensemble de techniques pour gerer, organiser, diriger, controler et planifier les activites. Selon Fayol : prevoir/planifier, organiser, commander, coordonner et controler. Outils : agenda partage, diagramme de `Gantt`, ecoute active, tableau de bord, methodes de gestion de projet (traditionnelle, Agile, PERT, chemin critique, PRINCE2, Lean).', 'Cours intégré Entreprenariat', 14),
  ('entreprenariat', 'Obstacles et risques de la creation', 'Trois grandes familles d''obstacles : techniques/materiels (besoin d''un business plan, d''une idee, d''un benchmark), le manque de temps, et les obstacles financiers (refus bancaire, ROI insuffisant). Solutions : `business angels`, aides etatiques, accompagnement. Argent et temps sont les deux contraintes principales de toute creation.', 'Cours intégré Entreprenariat', 15),
  ('droittravail', 'Définition et objet du droit du travail', 'Le droit du travail est l''ensemble des règles juridiques régissant les relations individuelles et collectives nées du travail salarié subordonné. Il ne s''applique qu''au travail exécuté pour le compte d''autrui, contre rémunération et sous l''autorité d''un employeur, à l''exclusion du travail indépendant et de la fonction publique régie par un statut propre.', 'Cours intégré Droit du Travail', 0),
  ('droittravail', 'Sources du droit du travail camerounais', 'Au Cameroun, la source principale est la loi n°92/007 du 14 août 1992 portant Code du travail, complétée par ses décrets d''application, les conventions collectives, le règlement intérieur de l''entreprise, le contrat de travail, les usages, la jurisprudence et les conventions internationales de l''OIT ratifiées. La Constitution et le Code civil ne sont que des sources subsidiaires.', 'Cours intégré Droit du Travail', 1),
  ('droittravail', 'Définition et éléments du contrat de travail', 'Le contrat de travail est la convention par laquelle une personne (le travailleur) s''engage à mettre son activité professionnelle sous la direction et l''autorité d''une autre (l''employeur) moyennant rémunération. Ses trois éléments essentiels et cumulatifs sont : la prestation de travail, la rémunération (salaire) et le lien de subordination juridique, ce dernier étant le critère déterminant.', 'Cours intégré Droit du Travail', 2),
  ('droittravail', 'Conditions de validité et objet licite', 'Comme tout contrat, le contrat de travail suppose le consentement, la capacité, un objet et une cause licites. L''objet et la cause doivent être conformes à l''ordre public et aux bonnes mœurs : un contrat dont l''objet est illicite (travail clandestin, activité interdite) est nul et ne produit aucun effet.', 'Cours intégré Droit du Travail', 3),
  ('droittravail', 'CDI, CDD et contrat d''apprentissage', 'Le CDI est conclu sans terme et constitue la forme normale du contrat. Le CDD est conclu pour une durée précise ou pour un ouvrage déterminé ; pour un travailleur de nationalité camerounaise, il ne peut être renouvelé qu''une seule fois et sa durée totale ne peut excéder 2 ans, faute de quoi il se mue en CDI. L''apprentissage vise la formation professionnelle d''un jeune par un maître d''apprentissage, sous contrat écrit obligatoire.', 'Cours intégré Droit du Travail', 4),
  ('droittravail', 'Période d''essai', 'La période d''essai permet à chaque partie d''apprécier l''autre avant l''engagement définitif ; elle doit être stipulée par écrit et sa durée est encadrée selon la catégorie professionnelle (jusqu''à six mois renouvellement compris pour les cadres). Pendant l''essai, le contrat peut être rompu librement, sans préavis ni indemnité de rupture, mais sans abus.', 'Cours intégré Droit du Travail', 5),
  ('droittravail', 'Droits et obligations des parties', 'L''employeur doit fournir le travail convenu, payer le salaire, assurer l''hygiène et la sécurité, déclarer et affilier le travailleur à la CNPS et respecter la dignité du salarié. Le travailleur doit exécuter personnellement et loyalement sa prestation, obéir aux ordres licites, respecter le règlement intérieur et observer une obligation de discrétion et de non-concurrence pendant l''exécution du contrat.', 'Cours intégré Droit du Travail', 6),
  ('droittravail', 'Durée du travail et heures supplémentaires', 'La durée légale du travail est fixée à 40 heures par semaine dans les établissements non agricoles. Les heures effectuées au-delà sont des heures supplémentaires donnant droit à une majoration de salaire (taux croissants selon les tranches et le travail de nuit, dimanche ou jour férié), dans la limite d''un contingent réglementaire.', 'Cours intégré Droit du Travail', 7),
  ('droittravail', 'Congés, repos et protection de la maternité', 'Le travailleur a droit à un repos hebdomadaire d''au moins 24 heures consécutives et à un congé payé acquis à raison d''un jour et demi ouvrable par mois de service effectif. La femme enceinte bénéficie d''un congé de maternité de quatorze semaines pendant lequel le contrat est suspendu, et elle perçoit des indemnités journalières servies par la CNPS, l''employeur ne pouvant la licencier en raison de sa grossesse.', 'Cours intégré Droit du Travail', 8),
  ('droittravail', 'Rémunération et SMIG', 'Le salaire comprend le salaire de base et ses accessoires (primes, indemnités, avantages en nature). Aucun salaire ne peut être inférieur au SMIG fixé par voie réglementaire. Du salaire brut sont déduits les prélèvements sociaux (cotisation CNPS part salariale) et fiscaux (impôts sur les salaires) pour obtenir le salaire net effectivement perçu.', 'Cours intégré Droit du Travail', 9),
  ('droittravail', 'Suspension du contrat de travail', 'Certains événements suspendent le contrat sans le rompre : maladie, accident, congé de maternité, mise à pied disciplinaire, force majeure, exercice d''un mandat. Pendant la suspension, l''obligation de fournir le travail et, le plus souvent, celle de payer le salaire sont gelées, mais le lien contractuel et l''ancienneté sont en principe préservés.', 'Cours intégré Droit du Travail', 10),
  ('droittravail', 'Rupture du contrat : démission, licenciement, préavis, indemnités', 'La démission est la rupture à l''initiative du travailleur ; le licenciement, celle à l''initiative de l''employeur, qui doit reposer sur un motif légitime. Sauf faute lourde, la partie qui rompt doit respecter un préavis ou en payer l''indemnité compensatrice. En cas de licenciement non motivé par une faute lourde, le travailleur a droit à l''indemnité de licenciement, à l''indemnité de préavis et au solde de tout compte ; en cas de faute lourde, il ne reçoit que son certificat de travail et son solde de tout compte (salaires dus, congés payés).', 'Cours intégré Droit du Travail', 11),
  ('droittravail', 'Licenciement économique et compression de personnel', 'Lorsqu''une entreprise réduit ses charges pour des difficultés conjoncturelles ou structurelles, elle peut procéder à un licenciement pour motif économique (compression de personnel) selon une procédure d''ordre : information des délégués du personnel, recherche de critères objectifs (ancienneté, charges de famille, aptitude) et notification à l''inspecteur du travail, le travailleur conservant ses indemnités.', 'Cours intégré Droit du Travail', 12),
  ('droittravail', 'Conflits collectifs, grève et règlement', 'Les conflits collectifs opposant un groupe de travailleurs à l''employeur sont d''abord soumis à une procédure de conciliation puis d''arbitrage. La grève, cessation collective et concertée du travail pour des revendications professionnelles, n''est licite qu''après épuisement des voies de règlement amiable ; exercée régulièrement, elle suspend le contrat sans le rompre.', 'Cours intégré Droit du Travail', 13),
  ('droittravail', 'Représentation des travailleurs et syndicats', 'Les travailleurs sont représentés par les délégués du personnel, élus dans tout établissement employant un nombre minimal de salariés, qui présentent les réclamations individuelles et collectives. La liberté syndicale est garantie : les syndicats défendent les intérêts professionnels et négocient les conventions collectives, leurs dirigeants bénéficiant d''une protection contre le licenciement.', 'Cours intégré Droit du Travail', 14),
  ('droittravail', 'Inspection et tribunal du travail', 'L''inspecteur du travail contrôle l''application de la législation, concilie les parties et constate les infractions ; sa saisine est souvent un préalable obligatoire avant le contentieux. Le tribunal du travail, juridiction spécialisée, tranche les litiges individuels du travail après échec de la tentative de conciliation devant l''inspecteur.', 'Cours intégré Droit du Travail', 15),
  ('multimedia', 'Infographie', 'L''infographie est le domaine de la creation d''images numeriques assistee par ordinateur ; c''est aussi, au sens du cours, la communication par l''image. Elle articule une dimension technique (logiciels, formats) et une dimension semiotique (porter un sens via l''image).', 'Cours intégré Multimédia & Infographie', 0),
  ('multimedia', 'Image numerique', 'Une image numerique est toute image acquise, creee, traitee et stockee sous forme binaire (suite de 0 et 1). Une image au sens general est une representation visuelle, voire mentale, de quelque chose : objet, etre vivant ou concept.', 'Cours intégré Multimédia & Infographie', 1),
  ('multimedia', 'Signe et semiologie', 'Un signe est une marque, naturelle ou conventionnelle, designant pour quelqu''un un objet ou un concept et destinee a etre interpretee par un tiers. La semiologie (ou semeiologie) est l''etude des signes linguistiques, verbaux (avec parole) et non verbaux (sans parole).', 'Cours intégré Multimédia & Infographie', 2),
  ('multimedia', 'Signifiant et signifie', 'En linguistique (Saussure), le signe est la reunion d''un signifiant et d''un signifie. Le signifiant est l''image acoustique du mot, sa face materielle ; le signifie est le concept, la representation mentale de la chose. En infographie, l''image (signifiant visuel) doit transmettre le bon signifie.', 'Cours intégré Multimédia & Infographie', 3),
  ('multimedia', 'Monosemie et polysemie', 'La monosemie qualifie un mot/une expression a un seul sens (un signifiant pour un signifie), ex. la logique 1+1=2. La polysemie qualifie un signifiant a plusieurs signifies, ex. une croix dans l''art ; une image polysemique appelle un contexte pour fixer le sens vise.', 'Cours intégré Multimédia & Infographie', 4),
  ('multimedia', 'Notion de projet et demarche', 'Concevoir une image part d''un theme pour aboutir a un visuel via une demarche structuree : I - Analyse (A. Definition des mots-cles, B. Choix des elements majeurs refletant le sens du theme) puis II - Avant-projet, materialisation caricaturale associant des images aux elements majeurs retenus.', 'Cours intégré Multimédia & Infographie', 5),
  ('multimedia', 'Supports de communication', 'Un support de communication est tout ce qui sert a conserver, transporter et transmettre une information. On distingue deux grands groupes : ceux lies a la chaine graphique (impression) et ceux lies a l''edition numerique (ecrans/web).', 'Cours intégré Multimédia & Infographie', 6),
  ('multimedia', 'Chaine graphique vs edition numerique', 'La chaine graphique est l''ensemble des professions intervenant de la conception a la finalisation d''un produit imprime en multiples exemplaires. L''edition numerique est l''ensemble des pratiques de production, mise en forme, circulation et legitimation d''un contenu dans un environnement numerique (livre numerique, site web).', 'Cours intégré Multimédia & Infographie', 7),
  ('multimedia', 'Format A4 et chaine graphique', 'La chaine graphique s''appuie sur un element de mesure de dimension : le format A4 (210 x 297 mm). Par convention il se presente en portrait (presentation a la francaise) et peut se presenter en paysage (a l''italienne). L''A4 a des multiples (A3, A2, A1, A0) et sous-multiples (A5, A6...).', 'Cours intégré Multimédia & Infographie', 8),
  ('multimedia', 'Resolution et pixel', 'Le pixel (picture element) est la plus petite unite d''une image matricielle. La resolution est un rapport de densite : le nombre de pixels affichables/imprimables dans un pouce (2,54 cm), exprime en `ppp/dpi`. Reperes usuels : 72 dpi pour l''ecran/web, 300 dpi pour l''impression de qualite.', 'Cours intégré Multimédia & Infographie', 9),
  ('multimedia', 'Definition vs resolution', 'La definition d''une image est son nombre total de pixels (ex. `1920 x 1080`), independante du support. La resolution lie ces pixels a une dimension physique (dpi). Pour une definition fixe, augmenter la resolution reduit la taille imprimee, et inversement.', 'Cours intégré Multimédia & Infographie', 10),
  ('multimedia', 'Matriciel (bitmap) vs vectoriel', 'L''image matricielle (bitmap : JPEG, PNG, GIF, TIFF, PSD) est une grille de pixels, riche en nuances mais pixellisee a l''agrandissement (dependante de la resolution). L''image vectorielle (SVG, AI, EPS) decrit des formes par des equations mathematiques (courbes de Bezier) : redimensionnable sans perte, ideale pour logos et typographie.', 'Cours intégré Multimédia & Infographie', 11),
  ('multimedia', 'Profondeur de couleur et modes colorimetriques', 'La profondeur de couleur est le nombre de bits codant chaque pixel (1 bit = 2 couleurs, 8 bits = 256, 24 bits = ~16,7 millions en `true color`). Modes : RVB (additif, Rouge-Vert-Bleu, ecrans), CMJN (soustractif, Cyan-Magenta-Jaune-Noir, impression), TSL/TSV (Teinte-Saturation-Luminosite, modele intuitif de selection).', 'Cours intégré Multimédia & Infographie', 12),
  ('multimedia', 'Formats et compression', 'Compression sans perte (PNG, GIF, TIFF) : aucune degradation, fichiers plus lourds. Compression avec perte (JPEG) : taux de compression eleve mais artefacts, ideal pour les photos. GIF gere 256 couleurs + animation + transparence binaire ; PNG la transparence alpha ; SVG est vectoriel ; PSD est le format natif (calques) de Photoshop.', 'Cours intégré Multimédia & Infographie', 13),
  ('multimedia', 'Logiciels et PAO', 'Les logiciels du cours sont Adobe Photoshop (retouche matricielle), Adobe Illustrator (dessin vectoriel) et QuarkXPress (mise en page/PAO) ; GIMP est l''alternative libre a Photoshop. La PAO (Publication Assistee par Ordinateur) designe la creation de documents destines a l''impression via des logiciels de mise en page (InDesign, QuarkXPress).', 'Cours intégré Multimédia & Infographie', 14);
